INSERT [dbo].[Articles] ([Id], [Title], [Slug], [Content], [CategoryId], [AuthorId], [Status], [CreatedAt], [PublishedAt], [Excerpt], [FeaturedImage]) VALUES (5, N'Phường Cao Lãnh chú trọng bảo tồn và phát huy giá trị di tích lịch sử.', N'bao-ton-di-tich-phuong-cao-lanh', N'<p class="ql-align-justify"><span style="color: rgb(34, 34, 34);">Phường&nbsp;Cao&nbsp;Lãnh&nbsp;hiện&nbsp;có&nbsp;11&nbsp;di&nbsp;tích&nbsp;lịch&nbsp;sử,&nbsp;văn&nbsp;hóa,&nbsp;trong&nbsp;đó,&nbsp;1&nbsp;di&nbsp;tích&nbsp;quốc&nbsp;gia&nbsp;đặc&nbsp;biệt&nbsp;là&nbsp;Di&nbsp;tích&nbsp;lịch&nbsp;sử&nbsp;Mộ&nbsp;Cụ&nbsp;Phó&nbsp;bảng&nbsp;Nguyễn&nbsp;Sinh&nbsp;Sắc;&nbsp;2&nbsp;di&nbsp;tích&nbsp;quốc&nbsp;gia&nbsp;là&nbsp;Mộ&nbsp;và&nbsp;Đền&nbsp;thờ&nbsp;ông,&nbsp;bà&nbsp;Đỗ&nbsp;Công&nbsp;Tường&nbsp;và&nbsp;Địa&nbsp;điểm&nbsp;Tập&nbsp;kết&nbsp;ra&nbsp;Bắc&nbsp;năm&nbsp;1954&nbsp;tại&nbsp;Cao&nbsp;Lãnh;&nbsp;8&nbsp;di&nbsp;tích&nbsp;cấp&nbsp;tỉnh.&nbsp;</span></p><p class="ql-align-center"><span style="color: rgb(0, 0, 0);"><img src="https://cdn2.baodongthap.vn/image/ckeditor/2025/20251215/files/wm_4_img_20251028_085655mo1.jpg" height="600" width="1000"></span><span style="color: gray;">Học&nbsp;sinh&nbsp;Trường&nbsp;Trung&nbsp;học&nbsp;cơ&nbsp;sở&nbsp;Nguyễn&nbsp;Thị&nbsp;Lựu&nbsp;(phường&nbsp;Cao&nbsp;Lãnh)&nbsp;viếng,&nbsp;thắp&nbsp;hương&nbsp;tại&nbsp;Mộ&nbsp;Cụ&nbsp;Phó&nbsp;bảng&nbsp;Nguyễn&nbsp;Sinh&nbsp;Sắc.</span></p><p class="ql-align-justify"><span style="color: rgb(34, 34, 34);">Công&nbsp;tác&nbsp;bảo&nbsp;tồn,&nbsp;trùng&nbsp;tu&nbsp;các&nbsp;di&nbsp;tích&nbsp;lịch&nbsp;sử&nbsp;trên&nbsp;địa&nbsp;bàn&nbsp;được&nbsp;UBND&nbsp;TP.&nbsp;Cao&nbsp;Lãnh&nbsp;(trước&nbsp;đây)&nbsp;và&nbsp;phường&nbsp;Cao&nbsp;Lãnh&nbsp;hiện&nbsp;nay&nbsp;quan&nbsp;tâm&nbsp;thực&nbsp;hiện.&nbsp;Trước&nbsp;khi&nbsp;thành&nbsp;lập&nbsp;phường&nbsp;Cao&nbsp;Lãnh,&nbsp;UBND&nbsp;TP.&nbsp;Cao&nbsp;Lãnh&nbsp;(cũ)&nbsp;làm&nbsp;chủ&nbsp;đầu&nbsp;tư&nbsp;thực&nbsp;hiện&nbsp;trùng&nbsp;tu,&nbsp;tôn&nbsp;tạo&nbsp;Khu&nbsp;mộ&nbsp;Cụ&nbsp;Nguyễn&nbsp;Quang&nbsp;Diêu&nbsp;với&nbsp;các&nbsp;hạng&nbsp;mục:&nbsp;Sơn&nbsp;phần&nbsp;nhà&nbsp;mồ,&nbsp;cải&nbsp;tạo,&nbsp;sửa&nbsp;chữa&nbsp;cổng,&nbsp;hàng&nbsp;rào,&nbsp;sân,&nbsp;bồn&nbsp;hoa,&nbsp;cột&nbsp;cờ,&nbsp;hệ&nbsp;thống&nbsp;điện&nbsp;chiếu&nbsp;sáng,&nbsp;tam&nbsp;cấp&nbsp;nhà&nbsp;chính;&nbsp;trùng&nbsp;tu&nbsp;chính&nbsp;điện&nbsp;và&nbsp;nhà&nbsp;khói&nbsp;Đình&nbsp;Tân&nbsp;Tịch;&nbsp;xây&nbsp;mới&nbsp;nhà&nbsp;truyền&nbsp;thống&nbsp;và&nbsp;nhà&nbsp;lưu&nbsp;niệm&nbsp;Khu&nbsp;lưu&nbsp;niệm&nbsp;Chi&nbsp;bộ&nbsp;An&nbsp;Nam&nbsp;Cộng&nbsp;sản&nbsp;Đảng…</span></p><p class="ql-align-justify"><span style="color: rgb(34, 34, 34);">Những&nbsp;di&nbsp;tích&nbsp;lịch&nbsp;sử&nbsp;trên&nbsp;địa&nbsp;bàn&nbsp;phường&nbsp;Cao&nbsp;Lãnh&nbsp;có&nbsp;nhiều&nbsp;giá&nbsp;trị&nbsp;về&nbsp;kiến&nbsp;trúc,&nbsp;lịch&nbsp;sử,&nbsp;văn&nbsp;hóa&nbsp;vẫn&nbsp;còn&nbsp;nguyên&nbsp;giá&nbsp;trị,&nbsp;có&nbsp;vai&nbsp;trò&nbsp;quan&nbsp;trọng&nbsp;đối&nbsp;với&nbsp;đời&nbsp;sống&nbsp;cộng&nbsp;đồng&nbsp;hôm&nbsp;nay&nbsp;và&nbsp;thế&nbsp;hệ&nbsp;mai&nbsp;sau.&nbsp;</span></p><p class="ql-align-justify"><span style="color: rgb(34, 34, 34);">Các&nbsp;di&nbsp;tích&nbsp;lịch&nbsp;sử&nbsp;đã&nbsp;trở&nbsp;thành&nbsp;“Địa&nbsp;chỉ&nbsp;đỏ”&nbsp;giáo&nbsp;dục&nbsp;truyền&nbsp;thống&nbsp;cho&nbsp;thế&nbsp;hệ&nbsp;trẻ.&nbsp;Hằng&nbsp;tháng,&nbsp;các&nbsp;ban,&nbsp;ngành,&nbsp;các&nbsp;tổ&nbsp;chức&nbsp;chính&nbsp;trị&nbsp;-&nbsp;xã&nbsp;hội&nbsp;của&nbsp;phường&nbsp;Cao&nbsp;Lãnh&nbsp;thường&nbsp;xuyên&nbsp;tổ&nbsp;chức&nbsp;các&nbsp;hoạt&nbsp;động&nbsp;sinh&nbsp;hoạt&nbsp;Chi&nbsp;bộ,&nbsp;Chi&nbsp;đoàn,&nbsp;Chi&nbsp;hội,&nbsp;tổ&nbsp;chức&nbsp;lễ&nbsp;kết&nbsp;nạp&nbsp;đảng&nbsp;viên,&nbsp;cùng&nbsp;các&nbsp;chuyến&nbsp;về&nbsp;nguồn&nbsp;tại&nbsp;các&nbsp;di&nbsp;tích&nbsp;lịch&nbsp;sử,&nbsp;văn&nbsp;hóa.&nbsp;</span></p><p class="ql-align-justify"><span style="color: rgb(34, 34, 34);">Tại&nbsp;đây,&nbsp;nhiều&nbsp;đoàn&nbsp;viên,&nbsp;thanh&nbsp;niên,&nbsp;học&nbsp;sinh&nbsp;được&nbsp;lắng&nbsp;nghe&nbsp;những&nbsp;câu&nbsp;chuyện&nbsp;về&nbsp;lịch&nbsp;sử,&nbsp;truyền&nbsp;thống&nbsp;hào&nbsp;hùng&nbsp;của&nbsp;dân&nbsp;tộc,&nbsp;tinh&nbsp;thần&nbsp;yêu&nbsp;nước,&nbsp;buất&nbsp;khuất&nbsp;của&nbsp;các&nbsp;bậc&nbsp;tiền&nbsp;nhân.&nbsp;</span></p><p class="ql-align-justify"><span style="color: rgb(34, 34, 34);">Từ&nbsp;đó,&nbsp;giáo&nbsp;dục,&nbsp;thắp&nbsp;lên&nbsp;trong&nbsp;các&nbsp;em&nbsp;ngọn&nbsp;lửa&nbsp;nhiệt&nbsp;huyết,&nbsp;lòng&nbsp;yêu&nbsp;nước&nbsp;và&nbsp;niềm&nbsp;tự&nbsp;hào&nbsp;dân&nbsp;tộc.</span></p><p class="ql-align-center"><span style="color: rgb(0, 0, 0);"><img src="https://cdn2.baodongthap.vn/image/ckeditor/2025/20251215/files/wm_5_img_20251028_0856551.jpg" height="600" width="1000"></span><span style="color: gray;">Học&nbsp;sinh&nbsp;Trường&nbsp;Trung&nbsp;học&nbsp;cơ&nbsp;sở&nbsp;Nguyễn&nbsp;Thị&nbsp;Lưu&nbsp;(phường&nbsp;Cao&nbsp;Lãnh)&nbsp;nghe&nbsp;thuyết&nbsp;minh&nbsp;về&nbsp;cuộc&nbsp;đời,&nbsp;sự&nbsp;nghiệp&nbsp;của&nbsp;Cụ&nbsp;Phó&nbsp;bảng&nbsp;Nguyễn&nbsp;Sinh&nbsp;Sắc.&nbsp;</span></p><p class="ql-align-justify"><span style="color: rgb(34, 34, 34);">Phường&nbsp;đoàn&nbsp;Cao&nbsp;Lãnh&nbsp;và&nbsp;Chi&nbsp;đoàn,&nbsp;Chi&nbsp;hội&nbsp;các&nbsp;khóm&nbsp;thường&nbsp;xuyên&nbsp;tổ&nbsp;chức&nbsp;các&nbsp;hoạt&nbsp;động&nbsp;sinh&nbsp;hoạt,&nbsp;về&nbsp;nguồn&nbsp;tại&nbsp;các&nbsp;di&nbsp;tích&nbsp;lịch&nbsp;sử&nbsp;trên&nbsp;địa&nbsp;bàn.&nbsp;</span></p><p class="ql-align-justify"><span style="color: rgb(34, 34, 34);">Nhân&nbsp;các&nbsp;ngày&nbsp;lễ,&nbsp;kỷ&nbsp;niệm,&nbsp;lễ&nbsp;giỗ&nbsp;các&nbsp;bậc&nbsp;tiền&nbsp;nhân&nbsp;tổ&nbsp;chức&nbsp;cho&nbsp;các&nbsp;đoàn&nbsp;viên,&nbsp;thanh&nbsp;niên&nbsp;quét&nbsp;dọn,&nbsp;vệ&nbsp;sinh&nbsp;tại&nbsp;các&nbsp;Bia&nbsp;tưởng&nbsp;niệm&nbsp;anh&nbsp;hùng&nbsp;liệt&nbsp;sĩ,&nbsp;Đền&nbsp;thờ&nbsp;ông,&nbsp;bà&nbsp;Đỗ&nbsp;Công&nbsp;Tường...&nbsp;</span></p><p class="ql-align-justify"><span style="color: rgb(34, 34, 34);">Đồng&nbsp;thời,&nbsp;tuyên&nbsp;truyền,&nbsp;giáo&nbsp;dục&nbsp;đoàn&nbsp;viên,&nbsp;thanh&nbsp;niên&nbsp;về&nbsp;truyền&nbsp;thống&nbsp;lịch&nbsp;sử&nbsp;của&nbsp;dân&nbsp;tộc,&nbsp;góp&nbsp;phần&nbsp;giáo&nbsp;dục&nbsp;lòng&nbsp;yêu&nbsp;nước&nbsp;cho&nbsp;thế&nbsp;hệ&nbsp;trẻ.&nbsp;</span></p><p class="ql-align-justify"><span style="color: rgb(34, 34, 34);">Bên&nbsp;cạnh&nbsp;đó,&nbsp;phường&nbsp;Cao&nbsp;Lãnh&nbsp;còn&nbsp;tuyên&nbsp;truyền,&nbsp;quảng&nbsp;bá&nbsp;về&nbsp;hình&nbsp;ảnh&nbsp;của&nbsp;các&nbsp;di&nbsp;tích&nbsp;lịch&nbsp;sử&nbsp;gắn&nbsp;với&nbsp;phát&nbsp;triển&nbsp;du&nbsp;lịch.&nbsp;</span></p><p class="ql-align-justify"><span style="color: rgb(34, 34, 34);">Thông&nbsp;qua&nbsp;các&nbsp;lễ&nbsp;hội&nbsp;văn&nbsp;hóa,&nbsp;lễ&nbsp;giỗ&nbsp;các&nbsp;bậc&nbsp;tiền&nbsp;nhân,&nbsp;đặc&nbsp;biệt&nbsp;là&nbsp;Lễ&nbsp;giỗ&nbsp;ông,&nbsp;bà&nbsp;Đỗ&nbsp;Công&nbsp;Tường,&nbsp;Lễ&nbsp;giỗ&nbsp;Cụ&nbsp;Phó&nbsp;bảng&nbsp;Nguyễn&nbsp;Sinh&nbsp;Sắc&nbsp;hằng&nbsp;năm,&nbsp;phường&nbsp;Cao&nbsp;Lãnh&nbsp;tổ&nbsp;chức&nbsp;nhiều&nbsp;hoạt&nbsp;động&nbsp;văn&nbsp;hóa,&nbsp;văn&nbsp;nghệ&nbsp;đặc&nbsp;sắc&nbsp;như:&nbsp;Biểu&nbsp;diễn&nbsp;văn&nbsp;nghệ&nbsp;tái&nbsp;hiện&nbsp;cuộc&nbsp;đời,&nbsp;công&nbsp;lao&nbsp;to&nbsp;lớn&nbsp;của&nbsp;ông,&nbsp;bà&nbsp;Đỗ&nbsp;Công&nbsp;Tường;&nbsp;phục&nbsp;dựng&nbsp;tiểu&nbsp;cảnh&nbsp;tái&nbsp;hiện&nbsp;cảnh&nbsp;mua&nbsp;bán&nbsp;tại&nbsp;chợ&nbsp;vườn&nbsp;quýt;&nbsp;giao&nbsp;lưu&nbsp;đờn&nbsp;ca&nbsp;tài&nbsp;tử,&nbsp;biểu&nbsp;diễn&nbsp;lân&nbsp;sư&nbsp;rồng,&nbsp;thể&nbsp;dục&nbsp;dưỡng&nbsp;sinh,&nbsp;trưng&nbsp;bày&nbsp;sản&nbsp;phẩm&nbsp;OCOP…&nbsp;góp&nbsp;phần&nbsp;phục&nbsp;vụ&nbsp;du&nbsp;khách&nbsp;đến&nbsp;viếng,&nbsp;tham&nbsp;quan,&nbsp;trải&nbsp;nghiệm.&nbsp;</span></p><p class="ql-align-justify"><span style="color: rgb(34, 34, 34);">Riêng&nbsp;Lễ&nbsp;giỗ&nbsp;ông,&nbsp;bà&nbsp;Đỗ&nbsp;Công&nbsp;Tường&nbsp;lần&nbsp;thứ&nbsp;205&nbsp;năm&nbsp;2025&nbsp;thu&nbsp;hút&nbsp;trên&nbsp;230.000&nbsp;lượt&nbsp;khách.&nbsp;Qua&nbsp;đó,&nbsp;kích&nbsp;cầu&nbsp;phát&nbsp;triển&nbsp;du&nbsp;lịch&nbsp;và&nbsp;quảng&nbsp;bá&nbsp;văn&nbsp;hóa,&nbsp;con&nbsp;người&nbsp;vùng&nbsp;đất&nbsp;Cao&nbsp;Lãnh&nbsp;đến&nbsp;du&nbsp;khách.&nbsp;</span></p><p class="ql-align-justify"><span style="color: rgb(34, 34, 34);">Ngoài&nbsp;ra,&nbsp;phường&nbsp;Cao&nbsp;Lãnh&nbsp;còn&nbsp;khai&nbsp;thác&nbsp;bến&nbsp;tàu&nbsp;tại&nbsp;Di&nbsp;tích&nbsp;lịch&nbsp;sử&nbsp;quốc&nbsp;gia&nbsp;Địa&nbsp;điểm&nbsp;Tập&nbsp;kết&nbsp;ra&nbsp;Bắc&nbsp;năm&nbsp;1954&nbsp;tại&nbsp;Cao&nbsp;Lãnh&nbsp;để&nbsp;kết&nbsp;nối&nbsp;du&nbsp;lịch&nbsp;đưa&nbsp;khách&nbsp;tham&nbsp;quan&nbsp;Chợ&nbsp;cù&nbsp;lao&nbsp;Tân&nbsp;Thuận&nbsp;Đông&nbsp;vào&nbsp;thứ&nbsp;Bảy&nbsp;hằng&nbsp;tuần&nbsp;nhằm&nbsp;phát&nbsp;triển&nbsp;du&nbsp;lịch.&nbsp;</span></p><p class="ql-align-justify"><span style="color: rgb(34, 34, 34);">Phó&nbsp;Trưởng&nbsp;phòng&nbsp;Văn&nbsp;hóa&nbsp;-&nbsp;Xã&nbsp;hội,&nbsp;phường&nbsp;Cao&nbsp;Lãnh&nbsp;Nguyễn&nbsp;Thị&nbsp;Yến&nbsp;Trinh&nbsp;cho&nbsp;biết:&nbsp;“Trong&nbsp;thời&nbsp;gian&nbsp;tới,&nbsp;phường&nbsp;sẽ&nbsp;tiếp&nbsp;tục&nbsp;quan&nbsp;tâm,&nbsp;thường&nbsp;xuyên&nbsp;theo&nbsp;dõi&nbsp;và&nbsp;thực&nbsp;hiện&nbsp;trung&nbsp;tu,&nbsp;tôn&nbsp;tạo&nbsp;các&nbsp;hạng&nbsp;mục&nbsp;bị&nbsp;xuống&nbsp;cấp&nbsp;tại&nbsp;các&nbsp;di&nbsp;tích&nbsp;lịch&nbsp;sử&nbsp;văn&nbsp;hóa&nbsp;trên&nbsp;địa&nbsp;bàn.&nbsp;</span></p><p class="ql-align-justify"><span style="color: rgb(34, 34, 34);">Khai&nbsp;thác&nbsp;các&nbsp;tiện&nbsp;ích&nbsp;trên&nbsp;không&nbsp;gian&nbsp;mạng&nbsp;để&nbsp;tuyên&nbsp;truyền,&nbsp;quảng&nbsp;bá&nbsp;hình&nbsp;ảnh&nbsp;các&nbsp;di&nbsp;tích&nbsp;lịch&nbsp;sử&nbsp;để&nbsp;mỗi&nbsp;người&nbsp;dân,&nbsp;đoàn&nbsp;viên,&nbsp;thanh&nbsp;niên,&nbsp;học&nbsp;sinh&nbsp;đến&nbsp;với&nbsp;các&nbsp;di&nbsp;tích&nbsp;lịch&nbsp;sử&nbsp;không&nbsp;chỉ&nbsp;tham&nbsp;quan&nbsp;mà&nbsp;còn&nbsp;hiểu&nbsp;biết&nbsp;thêm&nbsp;về&nbsp;truyền&nbsp;thống&nbsp;lịch&nbsp;sử,&nbsp;từ&nbsp;đó&nbsp;thắp&nbsp;lên&nbsp;ngọn&nbsp;lửa&nbsp;yêu&nbsp;nước,&nbsp;tinh&nbsp;thần&nbsp;cống&nbsp;hiến&nbsp;để&nbsp;xây&nbsp;dựng&nbsp;quê&nbsp;hương&nbsp;phát&nbsp;triển.&nbsp;</span></p><p class="ql-align-justify"><span style="color: rgb(34, 34, 34);">Bên&nbsp;cạnh&nbsp;đó,&nbsp;phường&nbsp;Cao&nbsp;Lãnh&nbsp;sẽ&nbsp;tập&nbsp;trung&nbsp;khai&nbsp;thác&nbsp;tối&nbsp;đa,&nbsp;phát&nbsp;triển&nbsp;các&nbsp;tour&nbsp;du&nbsp;lịch&nbsp;kết&nbsp;nối&nbsp;với&nbsp;các&nbsp;di&nbsp;tích&nbsp;lịch&nbsp;sử:&nbsp;Địa&nbsp;điểm&nbsp;tập&nbsp;kết&nbsp;ra&nbsp;Bắc&nbsp;tại&nbsp;Cao&nbsp;Lãnh&nbsp;năm&nbsp;1954,&nbsp;Khu&nbsp;lưu&nbsp;niệm&nbsp;Chi&nbsp;bộ&nbsp;An&nbsp;Nam&nbsp;Cộng&nbsp;sản&nbsp;Đảng,&nbsp;góp&nbsp;phần&nbsp;quảng&nbsp;bá&nbsp;hình&nbsp;ảnh&nbsp;phường&nbsp;Cao&nbsp;Lãnh&nbsp;nói&nbsp;riêng&nbsp;và&nbsp;vùng&nbsp;đất&nbsp;Cao&nbsp;Lãnh&nbsp;nói&nbsp;chung,&nbsp;qua&nbsp;đó&nbsp;góp&nbsp;phần&nbsp;gìn&nbsp;giữ&nbsp;và&nbsp;phát&nbsp;huy&nbsp;giá&nbsp;trị&nbsp;của&nbsp;các&nbsp;di&nbsp;tích&nbsp;lịch&nbsp;sử”.</span></p>', 1, 4, N'Published', CAST(N'2026-03-24T18:22:46.6859068' AS DateTime2), CAST(N'2026-03-24T19:00:58.7946840' AS DateTime2), N'Công tác bảo tồn di tích lịch sử tại phường Cao Lãnh góp phần giáo dục truyền thống và phát triển du lịch địa phương.', N'/uploads/b38083b1-b761-44ea-aa00-5f3496fc4883.jpg')
INSERT [dbo].[Articles] ([Id], [Title], [Slug], [Content], [CategoryId], [AuthorId], [Status], [CreatedAt], [PublishedAt], [Excerpt], [FeaturedImage]) VALUES (6, N'Nguồn gốc tên gọi Cao Lãnh và câu chuyện ông Đỗ Công Tường', N'nguon-goc-ten-goi-cao-lanh-va-cau-chuyen-ong-do-cong-tuong', N'<p class="ql-align-justify"><span style="color: rgb(55, 65, 81);">Danh&nbsp;xưng&nbsp;Cao&nbsp;Lãnh&nbsp;ngoài&nbsp;được&nbsp;đặt&nbsp;tên&nbsp;cho&nbsp;một&nbsp;huyện&nbsp;và&nbsp;thành&nbsp;phố&nbsp;thì&nbsp;còn&nbsp;được&nbsp;dùng&nbsp;cho&nbsp;rất&nbsp;nhiều&nbsp;địa&nbsp;điểm&nbsp;khác&nbsp;ở&nbsp;tỉnh&nbsp;Đồng&nbsp;Tháp.&nbsp;Nguồn&nbsp;gốc&nbsp;danh&nbsp;xưng&nbsp;này&nbsp;là&nbsp;những&nbsp;câu&nbsp;chuyện&nbsp;gắn&nbsp;liền&nbsp;với&nbsp;vợ&nbsp;chồng&nbsp;ông&nbsp;bà&nbsp;chủ&nbsp;chợ&nbsp;Cao&nbsp;Lãnh&nbsp;Đỗ&nbsp;Công&nbsp;Tường&nbsp;(?&nbsp;-&nbsp;1820),&nbsp;người&nbsp;mà&nbsp;sau&nbsp;khi&nbsp;mất&nbsp;được&nbsp;được&nbsp;người&nbsp;dân&nbsp;lập&nbsp;đền&nbsp;thờ,&nbsp;được&nbsp;vua&nbsp;triều&nbsp;Nguyễn&nbsp;phong&nbsp;là&nbsp;Thành&nbsp;hoàng.</span></p><p class="ql-align-justify"><strong style="color: rgb(17, 24, 39);">Nguyện&nbsp;chết&nbsp;thay&nbsp;cho&nbsp;dân</strong></p><p class="ql-align-justify"><span style="color: rgb(55, 65, 81);">Theo&nbsp;các&nbsp;tài&nbsp;liệu&nbsp;ghi&nbsp;chép,&nbsp;ông&nbsp;Đỗ&nbsp;Công&nbsp;Tường&nbsp;tục&nbsp;danh&nbsp;là&nbsp;Lãnh,&nbsp;tuy&nbsp;nhiên&nbsp;không&nbsp;rõ&nbsp;quê&nbsp;quán&nbsp;cụ&nbsp;thể,&nbsp;chỉ&nbsp;biết&nbsp;ông&nbsp;và&nbsp;vợ&nbsp;từ&nbsp;miền&nbsp;Trung&nbsp;vào&nbsp;lập&nbsp;nghiệp&nbsp;tại&nbsp;làng&nbsp;Mỹ&nbsp;Trà&nbsp;(nay&nbsp;thuộc&nbsp;phường&nbsp;2,&nbsp;TP&nbsp;Cao&nbsp;Lãnh,&nbsp;tỉnh&nbsp;Đồng&nbsp;Tháp)&nbsp;vào&nbsp;khoảng&nbsp;năm&nbsp;Đinh&nbsp;Sửu&nbsp;(1817),&nbsp;dưới&nbsp;triều&nbsp;vua&nbsp;Gia&nbsp;Long.</span></p><p class="ql-align-justify"><span style="color: rgb(55, 65, 81);">Sau&nbsp;nhiều&nbsp;năm&nbsp;cần&nbsp;cù&nbsp;chịu&nbsp;khó&nbsp;khai&nbsp;hoang,&nbsp;hai&nbsp;vợ&nbsp;chồng&nbsp;ông&nbsp;bà&nbsp;đã&nbsp;gầy&nbsp;dựng&nbsp;được&nbsp;vườn&nbsp;quýt&nbsp;rộng&nbsp;lớn,&nbsp;cây&nbsp;trái&nbsp;sum&nbsp;suê.&nbsp;Nhờ&nbsp;nguồn&nbsp;thu&nbsp;từ&nbsp;vườn&nbsp;cây&nbsp;trái&nbsp;mà&nbsp;cuộc&nbsp;sống&nbsp;gia&nbsp;đình&nbsp;ngày&nbsp;một&nbsp;khấm&nbsp;khá.&nbsp;Vườn&nbsp;quýt&nbsp;của&nbsp;ông&nbsp;bà&nbsp;tốt&nbsp;tươi&nbsp;mát&nbsp;mẻ,&nbsp;lại&nbsp;ở&nbsp;nơi&nbsp;thuận&nbsp;cả&nbsp;đường&nbsp;sông&nbsp;và&nbsp;đường&nbsp;bộ&nbsp;nên&nbsp;người&nbsp;dân&nbsp;xa&nbsp;gần&nbsp;thường&nbsp;tụ&nbsp;tập&nbsp;đến&nbsp;đây&nbsp;để&nbsp;mua&nbsp;bán,&nbsp;trao&nbsp;đổi&nbsp;nông&nbsp;sản&nbsp;hàng&nbsp;hóa.</span></p><p class="ql-align-justify"><span style="color: rgb(55, 65, 81);">Để&nbsp;giúp&nbsp;người&nbsp;dân&nbsp;thuận&nbsp;tiện&nbsp;bán&nbsp;buôn,&nbsp;hai&nbsp;ông&nbsp;bà&nbsp;bỏ&nbsp;tiền&nbsp;bạc&nbsp;công&nbsp;sức&nbsp;dựng&nbsp;lên&nbsp;những&nbsp;lều&nbsp;quán&nbsp;bằng&nbsp;cây&nbsp;lá.&nbsp;Từ&nbsp;ngày&nbsp;có&nbsp;lều&nbsp;trại&nbsp;làm&nbsp;nơi&nbsp;tránh&nbsp;nắng&nbsp;tránh&nbsp;mưa,&nbsp;người&nbsp;dân&nbsp;kéo&nbsp;nhau&nbsp;đến&nbsp;đây&nbsp;họp&nbsp;chợ&nbsp;mỗi&nbsp;lúc&nbsp;một&nbsp;đông.&nbsp;Dần&nbsp;dần&nbsp;các&nbsp;hiệu&nbsp;buôn&nbsp;bên&nbsp;chợ&nbsp;Hòa&nbsp;Thành&nbsp;(tức&nbsp;Hòa&nbsp;An&nbsp;bây&nbsp;giờ)&nbsp;cũng&nbsp;dời&nbsp;qua,&nbsp;làm&nbsp;cho&nbsp;khu&nbsp;vườn&nbsp;quýt&nbsp;ngày&nbsp;càng&nbsp;thêm&nbsp;tấp&nbsp;nập.&nbsp;Dần&nbsp;dà&nbsp;người&nbsp;ta&nbsp;gọi&nbsp;đây&nbsp;là&nbsp;chợ&nbsp;Vườn&nbsp;Quýt.</span></p><p class="ql-align-justify"><span style="color: rgb(55, 65, 81);">Dân&nbsp;làng&nbsp;cảm&nbsp;phục&nbsp;hai&nbsp;vợ&nbsp;chồng&nbsp;ông&nbsp;bà&nbsp;Đỗ&nbsp;Công&nbsp;Tường&nbsp;vì&nbsp;lòng&nbsp;nhân&nbsp;nghĩa,&nbsp;hay&nbsp;giúp&nbsp;đỡ&nbsp;người&nbsp;nghèo,&nbsp;tính&nbsp;tình&nbsp;thẳng&nbsp;thắn&nbsp;cương&nbsp;trực,&nbsp;nêncử&nbsp;ông&nbsp;làm&nbsp;chức&nbsp;Câu&nbsp;đương.&nbsp;Đây&nbsp;là&nbsp;chức&nbsp;vụ&nbsp;chuyên&nbsp;lo&nbsp;việc&nbsp;phân&nbsp;xử&nbsp;những&nbsp;việc&nbsp;kiện&nbsp;cáo&nbsp;nhỏ&nbsp;và&nbsp;các&nbsp;sự&nbsp;vụ&nbsp;trong&nbsp;phạm&nbsp;vi&nbsp;thôn&nbsp;làng.&nbsp;Sau&nbsp;người&nbsp;ta&nbsp;ghép&nbsp;chức&nbsp;vụ&nbsp;vào&nbsp;tục&nbsp;danh&nbsp;của&nbsp;ông,&nbsp;đọc&nbsp;thành&nbsp;Câu&nbsp;Lãnh,&nbsp;thường&nbsp;gọi&nbsp;ông&nbsp;là&nbsp;ông&nbsp;Câu&nbsp;Lãnh.</span></p><p class="ql-align-center"><a href="https://image.baophapluat.vn/uploaded/quynhluu/2021_12_08/2-2398.jpg" rel="noopener noreferrer" target="_blank" style="color: rgb(17, 24, 39);"><img src="https://image.baophapluat.vn/Uploaded/quynhluu/2021_12_08/2-2398.jpg" alt="Nguồn gốc tên gọi Cao Lãnh và chuyện vợ chồng chủ chợ được dân tôn thờ"></a></p><p class="ql-align-center"><em style="color: rgb(108, 117, 125);">Mộ&nbsp;hai&nbsp;ông&nbsp;bà&nbsp;chủ&nbsp;chợ&nbsp;trong&nbsp;khu&nbsp;di&nbsp;tích.</em></p><p class="ql-align-justify"><span style="color: rgb(55, 65, 81);">Lúc&nbsp;bấy&nbsp;giờ,&nbsp;châu&nbsp;Á&nbsp;xuất&nbsp;hiện&nbsp;một&nbsp;trận&nbsp;đại&nbsp;dịch&nbsp;tả&nbsp;vô&nbsp;cùng&nbsp;khủng&nbsp;khiếp,&nbsp;bắt&nbsp;đầu&nbsp;từ&nbsp;nằm&nbsp;1816&nbsp;kéo&nbsp;dào&nbsp;đến&nbsp;năm&nbsp;1826&nbsp;mới&nbsp;kết&nbsp;thúc.&nbsp;Sau&nbsp;khi&nbsp;càn&nbsp;quét&nbsp;nhiều&nbsp;nơi&nbsp;trên&nbsp;châu&nbsp;lục,&nbsp;năm&nbsp;1820&nbsp;dịch&nbsp;vào&nbsp;nước&nbsp;ta&nbsp;qua&nbsp;ngả&nbsp;cửa&nbsp;biển&nbsp;Hà&nbsp;Tiên.&nbsp;Theo&nbsp;thống&nbsp;kê&nbsp;của&nbsp;triều&nbsp;Nguyễn,&nbsp;đại&nbsp;dịch&nbsp;tả&nbsp;đã&nbsp;cướp&nbsp;đi&nbsp;206.835&nbsp;sinh&nbsp;mạng,&nbsp;chiếm&nbsp;khoảng&nbsp;3-4%&nbsp;dân&nbsp;số&nbsp;nước&nbsp;ta&nbsp;lúc&nbsp;bấy&nbsp;giờ.</span></p><p class="ql-align-justify"><span style="color: rgb(55, 65, 81);">Trong&nbsp;năm&nbsp;1820,&nbsp;nạn&nbsp;dịch&nbsp;tả&nbsp;xuất&nbsp;hiện&nbsp;ở&nbsp;Đồng&nbsp;Tháp&nbsp;và&nbsp;khắp&nbsp;vùng&nbsp;Nam&nbsp;bộ,&nbsp;hoành&nbsp;hành&nbsp;rất&nbsp;dữ&nbsp;dội.Dân&nbsp;chúng&nbsp;trong&nbsp;vùng&nbsp;nhiễm&nbsp;dịch&nbsp;bệnh&nbsp;chết&nbsp;rất&nbsp;nhiều,&nbsp;đâu&nbsp;đâu&nbsp;cũng&nbsp;bao&nbsp;trùm&nbsp;cảnh&nbsp;tượng&nbsp;vắng&nbsp;vẻ,&nbsp;ảm&nbsp;đạm,&nbsp;tiếng&nbsp;mõ&nbsp;kêu&nbsp;cứu&nbsp;cứ&nbsp;một&nbsp;lát&nbsp;lại&nbsp;thúc&nbsp;lên&nbsp;từng&nbsp;hồi.&nbsp;Người&nbsp;làng&nbsp;Mỹ&nbsp;Trà&nbsp;cũng&nbsp;không&nbsp;tránh&nbsp;khỏi&nbsp;thảm&nbsp;cảnh&nbsp;nhiều&nbsp;người&nbsp;chết&nbsp;vì&nbsp;dịch&nbsp;bệnh,&nbsp;có&nbsp;nhiều&nbsp;gia&nbsp;đình&nbsp;người&nbsp;chết&nbsp;gần&nbsp;hết.</span></p><p class="ql-align-justify"><span style="color: rgb(55, 65, 81);">Vốn&nbsp;giàu&nbsp;lòng&nbsp;thương&nbsp;người,&nbsp;nhìn&nbsp;cảnh&nbsp;thôn&nbsp;làng&nbsp;tang&nbsp;thương&nbsp;vì&nbsp;dịch&nbsp;bệnh,&nbsp;ông&nbsp;bà&nbsp;Đỗ&nbsp;Công&nbsp;Tường&nbsp;không&nbsp;nỡ&nbsp;khoanh&nbsp;tay&nbsp;đứng&nbsp;nhìn.&nbsp;Hai&nbsp;vợ&nbsp;chồng&nbsp;dốc&nbsp;hết&nbsp;tiền&nbsp;của&nbsp;tìm&nbsp;thuốc&nbsp;hay&nbsp;thầy&nbsp;giỏi&nbsp;về&nbsp;chạy&nbsp;chữa,&nbsp;hi&nbsp;vọng&nbsp;cứu&nbsp;người&nbsp;làng&nbsp;qua&nbsp;cơn&nbsp;hoạn&nbsp;nạn.&nbsp;Khi&nbsp;mọi&nbsp;phương&nbsp;thuốc&nbsp;đều&nbsp;bất&nbsp;lực&nbsp;trước&nbsp;dịch&nbsp;bệnh,&nbsp;ông&nbsp;bà&nbsp;quyết&nbsp;định&nbsp;ăn&nbsp;chay&nbsp;lập&nbsp;bàn&nbsp;cầu&nbsp;nguyện&nbsp;xin&nbsp;được&nbsp;chết&nbsp;thay&nbsp;cho&nbsp;dân.</span></p><p class="ql-align-justify"><span style="color: rgb(55, 65, 81);">Sở&nbsp;dĩ&nbsp;có&nbsp;chuyện&nbsp;này&nbsp;là&nbsp;bởi&nbsp;lúc&nbsp;bấy&nbsp;giờ,&nbsp;có&nbsp;quan&nbsp;niệm&nbsp;rằng&nbsp;bệnh&nbsp;tật&nbsp;là&nbsp;do&nbsp;trời&nbsp;đất,&nbsp;thần&nbsp;thánh&nbsp;quở&nbsp;phạt&nbsp;con&nbsp;dân.&nbsp;Truyền&nbsp;rằng,&nbsp;ngày&nbsp;mùng&nbsp;6&nbsp;tháng&nbsp;6&nbsp;năm&nbsp;Canh&nbsp;Thìn&nbsp;(1820),&nbsp;ông&nbsp;bà&nbsp;tắm&nbsp;gội&nbsp;sạch&nbsp;sẽ,&nbsp;ăn&nbsp;chay&nbsp;rồi&nbsp;lập&nbsp;bàn&nbsp;hương&nbsp;án&nbsp;giữa&nbsp;trời&nbsp;khấn&nbsp;nguyện,&nbsp;xin&nbsp;được&nbsp;lấy&nbsp;mạng&nbsp;sống&nbsp;của&nbsp;hai&nbsp;vợ&nbsp;chồng&nbsp;ra&nbsp;để&nbsp;đổi&nbsp;lấy&nbsp;sự&nbsp;an&nbsp;lành&nbsp;cho&nbsp;mọi&nbsp;người.</span></p><p class="ql-align-justify"><span style="color: rgb(55, 65, 81);">Sau&nbsp;3&nbsp;ngày&nbsp;ăn&nbsp;chay&nbsp;cầu&nbsp;nguyện,&nbsp;đến&nbsp;tối&nbsp;ngày&nbsp;mùng&nbsp;9&nbsp;thì&nbsp;bà&nbsp;mất,&nbsp;rạng&nbsp;sáng&nbsp;mùng&nbsp;10&nbsp;thì&nbsp;ông&nbsp;cũng&nbsp;qua&nbsp;đời.&nbsp;Tiếc&nbsp;thương&nbsp;ông&nbsp;bà&nbsp;không&nbsp;con&nbsp;cái,&nbsp;sống&nbsp;một&nbsp;đời&nbsp;nhân&nbsp;đức,&nbsp;người&nbsp;dân&nbsp;chôn&nbsp;cất&nbsp;ông&nbsp;bà&nbsp;cẩn&nbsp;thận&nbsp;ngay&nbsp;phía&nbsp;sau&nbsp;khu&nbsp;vực&nbsp;chợ&nbsp;Vườn&nbsp;Quýt.&nbsp;Tương&nbsp;truyền,&nbsp;chôn&nbsp;cất&nbsp;ông&nbsp;bà&nbsp;xong&nbsp;thì&nbsp;bệnh&nbsp;dịch&nbsp;cũng&nbsp;dần&nbsp;dần&nbsp;lùi&nbsp;xa,&nbsp;cuộc&nbsp;sống&nbsp;lần&nbsp;hồi&nbsp;bình&nbsp;yên&nbsp;trở&nbsp;lại&nbsp;như&nbsp;trước.</span></p><p class="ql-align-justify"><span style="color: rgb(55, 65, 81);">Dân&nbsp;làng&nbsp;cho&nbsp;là&nbsp;nhờ&nbsp;lòng&nbsp;thành&nbsp;của&nbsp;ông&nbsp;bà&nbsp;nguyện&nbsp;hiến&nbsp;mạng&nbsp;cho&nbsp;dân&nbsp;được&nbsp;sống,&nbsp;đã&nbsp;thấu&nbsp;đến&nbsp;Trời&nbsp;Phật&nbsp;nên&nbsp;dịch&nbsp;bệnh&nbsp;được&nbsp;đẩy&nbsp;lùi.&nbsp;Dân&nbsp;làng&nbsp;cùng&nbsp;nhau&nbsp;góp&nbsp;công&nbsp;góp&nbsp;của&nbsp;dựng&nbsp;miếu&nbsp;thờ&nbsp;gần&nbsp;bên&nbsp;mộ&nbsp;ông&nbsp;bà&nbsp;(nay&nbsp;là&nbsp;đại&nbsp;lộ&nbsp;Lê&nbsp;Lợi,&nbsp;phường&nbsp;2,&nbsp;TP&nbsp;Cao&nbsp;Lãnh),&nbsp;ngày&nbsp;đêm&nbsp;khói&nbsp;hương&nbsp;để&nbsp;tưởng&nbsp;nhớ&nbsp;công&nbsp;lao&nbsp;hai&nbsp;người.&nbsp;Và&nbsp;để&nbsp;tỏ&nbsp;lòng&nbsp;tôn&nbsp;kính,&nbsp;người&nbsp;ta&nbsp;không&nbsp;gọi&nbsp;tên&nbsp;thật&nbsp;nữa&nbsp;mà&nbsp;chỉ&nbsp;gọi&nbsp;ông&nbsp;bà&nbsp;Đỗ&nbsp;Công&nbsp;Tường&nbsp;là&nbsp;ông&nbsp;chủ&nbsp;bà&nbsp;chủ&nbsp;chợ&nbsp;Cao&nbsp;Lãnh,&nbsp;hay&nbsp;gọi&nbsp;ngắn&nbsp;là&nbsp;ông&nbsp;bà&nbsp;chủ&nbsp;chợ.</span></p><p class="ql-align-justify"><span style="color: rgb(55, 65, 81);">Người&nbsp;dân&nbsp;cũng&nbsp;lấy&nbsp;tên&nbsp;ông&nbsp;để&nbsp;gọi&nbsp;tên&nbsp;chợ&nbsp;Vườn&nbsp;Quýt,&nbsp;là&nbsp;chợ&nbsp;Câu&nbsp;Lãnh,&nbsp;tức&nbsp;chợ&nbsp;ông&nbsp;Câu&nbsp;đương&nbsp;tên&nbsp;Lãnh,&nbsp;lâu&nbsp;ngày&nbsp;do&nbsp;nói&nbsp;trại&nbsp;mà&nbsp;thành&nbsp;Cao&nbsp;Lãnh.&nbsp;Đầu&nbsp;tiên&nbsp;là&nbsp;chỉ&nbsp;tên&nbsp;ngôi&nbsp;chợ,&nbsp;lần&nbsp;hồi&nbsp;Cao&nbsp;Lãnh&nbsp;trở&nbsp;thành&nbsp;địa&nbsp;danh&nbsp;cho&nbsp;đến&nbsp;ngày&nbsp;nay.&nbsp;Ngoài&nbsp;được&nbsp;đặt&nbsp;tên&nbsp;cho&nbsp;huyện&nbsp;Cao&nbsp;Lãnh&nbsp;và&nbsp;TP&nbsp;Cao&nbsp;Lãnh,&nbsp;danh&nbsp;từ&nbsp;này&nbsp;còn&nbsp;gắn&nbsp;liền&nbsp;với&nbsp;rất&nbsp;nhiều&nbsp;địa&nbsp;điểm,&nbsp;đơn&nbsp;vị&nbsp;khác&nbsp;trên&nbsp;địa&nbsp;bàn.</span></p><p class="ql-align-justify"><strong style="color: rgb(17, 24, 39);">Dân&nbsp;tôn&nbsp;thờ,&nbsp;triều&nbsp;đình&nbsp;phong&nbsp;thần</strong></p><p class="ql-align-center"><a href="https://image.baophapluat.vn/uploaded/quynhluu/2021_12_08/3-4673.jpg" rel="noopener noreferrer" target="_blank" style="color: rgb(17, 24, 39);"><img src="https://image.baophapluat.vn/Uploaded/quynhluu/2021_12_08/3-4673.jpg" alt="Nguồn gốc tên gọi Cao Lãnh và chuyện vợ chồng chủ chợ được dân tôn thờ"></a><span style="color: rgb(55, 65, 81);">Tượng&nbsp;ông&nbsp;bà&nbsp;Đỗ&nbsp;Công&nbsp;Tường&nbsp;hiện&nbsp;đang&nbsp;thờ&nbsp;trong&nbsp;đền.</span></p><p class="ql-align-justify"><span style="color: rgb(55, 65, 81);">Vì&nbsp;lòng&nbsp;nhân&nbsp;đức,&nbsp;không&nbsp;tiếc&nbsp;sinh&nbsp;mạng&nbsp;mình&nbsp;vì&nbsp;nhân&nbsp;dân,&nbsp;ông&nbsp;bà&nbsp;Đỗ&nbsp;Công&nbsp;Tường&nbsp;chẳng&nbsp;những&nbsp;được&nbsp;nhân&nbsp;dân&nbsp;kính&nbsp;thờ&nbsp;mà&nbsp;còn&nbsp;được&nbsp;triều&nbsp;đình&nbsp;ghi&nbsp;nhận&nbsp;và&nbsp;phong&nbsp;thần.&nbsp;Năm&nbsp;1920,&nbsp;sau&nbsp;khi&nbsp;được&nbsp;nhân&nbsp;sĩ&nbsp;đệ&nbsp;trình&nbsp;công&nbsp;trạng&nbsp;lên&nbsp;triều&nbsp;đình,&nbsp;năm&nbsp;1935&nbsp;vua&nbsp;Bảo&nbsp;Đại&nbsp;ban&nbsp;sắc&nbsp;phong&nbsp;cho&nbsp;ông&nbsp;bà&nbsp;là:&nbsp;“Dực&nbsp;bảo&nbsp;Trung&nbsp;hưng&nbsp;Linh&nbsp;phò&nbsp;chi&nbsp;thần”.</span></p><p class="ql-align-justify"><span style="color: rgb(55, 65, 81);">Cụ&nbsp;thể:&nbsp;“Sắc&nbsp;cho&nbsp;xã&nbsp;Mỹ&nbsp;Trà,&nbsp;tỉnh&nbsp;Sa&nbsp;Đéc,&nbsp;thờ&nbsp;phụng&nbsp;vị&nbsp;thần&nbsp;có&nbsp;công&nbsp;khai&nbsp;lập&nbsp;chợ&nbsp;Câu&nbsp;Lãnh&nbsp;là&nbsp;Đỗ&nbsp;Công&nbsp;Tường,&nbsp;từ&nbsp;trước&nbsp;đã&nbsp;tỏ&nbsp;ra&nbsp;linh&nbsp;ứng&nbsp;rõ&nbsp;rệt.&nbsp;Nay&nbsp;ta&nbsp;kế&nbsp;nối&nbsp;cơ&nbsp;đồ,&nbsp;nghĩ&nbsp;nhớ&nbsp;đến&nbsp;công&nbsp;lao&nbsp;của&nbsp;thần,&nbsp;mới&nbsp;phong&nbsp;là&nbsp;Dực&nbsp;bảo&nbsp;Trung&nbsp;hưng&nbsp;Linh&nbsp;phò&nbsp;chi&nbsp;thần,&nbsp;chuẩn&nbsp;cho&nbsp;được&nbsp;thờ&nbsp;tự,&nbsp;ngõ&nbsp;hầu&nbsp;thần&nbsp;hãy&nbsp;che&nbsp;chở&nbsp;cho&nbsp;dân&nbsp;lành”.</span></p><p class="ql-align-justify"><span style="color: rgb(55, 65, 81);">Mộ&nbsp;và&nbsp;miếu&nbsp;thờ&nbsp;ông&nbsp;bà&nbsp;được&nbsp;nhân&nbsp;dân&nbsp;tu&nbsp;sửa,&nbsp;coi&nbsp;sóc&nbsp;suốt&nbsp;200&nbsp;năm&nbsp;qua.&nbsp;Năm&nbsp;2001,&nbsp;đền&nbsp;thờ&nbsp;được&nbsp;UBND&nbsp;tỉnh&nbsp;Đồng&nbsp;Tháp&nbsp;công&nbsp;nhận&nbsp;là&nbsp;Di&nbsp;tích&nbsp;lịch&nbsp;sử&nbsp;văn&nbsp;hóa&nbsp;cấp&nbsp;tỉnh.&nbsp;Đền&nbsp;thờ&nbsp;được&nbsp;trùng&nbsp;tu&nbsp;lần&nbsp;thứ&nbsp;5,&nbsp;cũng&nbsp;là&nbsp;lần&nbsp;mới&nbsp;nhất,&nbsp;diễn&nbsp;ra&nbsp;vào&nbsp;năm&nbsp;2012,&nbsp;hoàn&nbsp;thành&nbsp;năm&nbsp;2014,&nbsp;mang&nbsp;đến&nbsp;diện&nbsp;mạo&nbsp;bề&nbsp;thế,&nbsp;uy&nbsp;nghi.&nbsp;Đến&nbsp;năm&nbsp;2019,&nbsp;công&nbsp;trình&nbsp;Mộ&nbsp;và&nbsp;Đền&nbsp;thờ&nbsp;ông&nbsp;bà&nbsp;được&nbsp;công&nbsp;nhận&nbsp;là&nbsp;di&nbsp;tích&nbsp;quốc&nbsp;gia.</span></p><p class="ql-align-justify"><span style="color: rgb(55, 65, 81);">Tổng&nbsp;thể&nbsp;công&nbsp;trình&nbsp;gồm&nbsp;đền&nbsp;thờ,&nbsp;nhà&nbsp;khách,&nbsp;ngôi&nbsp;mộ&nbsp;của&nbsp;ông&nbsp;bà&nbsp;được&nbsp;xây&nbsp;dựng&nbsp;kiên&nbsp;cố,&nbsp;trang&nbsp;trí,&nbsp;chạm&nbsp;trổ&nbsp;nguy&nbsp;nga&nbsp;lộng&nbsp;lẫy,&nbsp;mang&nbsp;tính&nbsp;đặc&nbsp;trưng&nbsp;của&nbsp;đình,&nbsp;đền&nbsp;Nam&nbsp;bộ.&nbsp;Về&nbsp;mặt&nbsp;kiến&nbsp;trúc,&nbsp;đền&nbsp;thờ&nbsp;ông&nbsp;bà&nbsp;Đỗ&nbsp;Công&nbsp;Tường&nbsp;được&nbsp;xây&nbsp;dựng&nbsp;theo&nbsp;kiến&nbsp;trúc&nbsp;dân&nbsp;gian&nbsp;truyền&nbsp;thống&nbsp;mái&nbsp;chồng&nbsp;mái,&nbsp;với&nbsp;nhiều&nbsp;tầng&nbsp;mái&nbsp;lợp&nbsp;ngói&nbsp;thanh&nbsp;lưu&nbsp;ly,&nbsp;bờ&nbsp;nóc&nbsp;đắp&nbsp;nổi&nbsp;hình&nbsp;tượng&nbsp;lưỡng&nbsp;long&nbsp;chầu&nbsp;nhật,&nbsp;góc&nbsp;mái&nbsp;vuốt&nbsp;cong&nbsp;đắp&nbsp;nổi&nbsp;hình&nbsp;tượng&nbsp;hoa&nbsp;lá&nbsp;cách&nbsp;điệu&nbsp;thành&nbsp;rồng.</span></p><p class="ql-align-justify"><span style="color: rgb(55, 65, 81);">Điện&nbsp;thờ&nbsp;được&nbsp;trang&nbsp;trí&nbsp;lộng&nbsp;lẫy&nbsp;với&nbsp;các&nbsp;bức&nbsp;hoành&nbsp;phi,&nbsp;bao&nbsp;lam&nbsp;được&nbsp;chạm&nbsp;trổ&nbsp;tinh&nbsp;xảo&nbsp;sơn&nbsp;son&nbsp;thếp&nbsp;vàng&nbsp;theo&nbsp;đề&nbsp;tài&nbsp;tứ&nbsp;linh&nbsp;hay&nbsp;tứ&nbsp;quý.&nbsp;Khám&nbsp;thờ&nbsp;ông&nbsp;bà&nbsp;Đỗ&nbsp;Công&nbsp;Tường&nbsp;được&nbsp;chạm&nbsp;trổ&nbsp;hình&nbsp;song&nbsp;long&nbsp;tranh&nbsp;châu&nbsp;và&nbsp;tứ&nbsp;linh&nbsp;long,&nbsp;lân,&nbsp;quy,&nbsp;phụng&nbsp;cùng&nbsp;những&nbsp;họa&nbsp;tiết&nbsp;hoa&nbsp;văn&nbsp;tinh&nbsp;xảo&nbsp;được&nbsp;sơn&nbsp;son&nbsp;thếp&nbsp;vàng&nbsp;rực&nbsp;rỡ.</span></p><p class="ql-align-justify"><span style="color: rgb(55, 65, 81);">Các&nbsp;bàn&nbsp;thờ&nbsp;đều&nbsp;được&nbsp;cẩn&nbsp;ốc&nbsp;xà&nbsp;cừ&nbsp;với&nbsp;đề&nbsp;tài&nbsp;hoa&nbsp;lá&nbsp;chim&nbsp;muông,&nbsp;trên&nbsp;các&nbsp;thân&nbsp;cột&nbsp;đều&nbsp;có&nbsp;câu&nbsp;đối&nbsp;bằng&nbsp;chữ&nbsp;Hán&nbsp;được&nbsp;sơn&nbsp;son&nbsp;thếp&nbsp;vàng.&nbsp;Đặc&nbsp;biệt,&nbsp;đền&nbsp;thờ&nbsp;còn&nbsp;lưu&nbsp;giữ&nbsp;sắc&nbsp;vua&nbsp;Bảo&nbsp;Đại&nbsp;phong&nbsp;cho&nbsp;ông&nbsp;Đỗ&nbsp;Công&nbsp;Tường&nbsp;là&nbsp;“Dực&nbsp;bảo&nbsp;Trung&nbsp;hưng&nbsp;Linh&nbsp;phò&nbsp;chi&nbsp;thần”&nbsp;vào&nbsp;năm&nbsp;1935.</span></p><p class="ql-align-justify"><span style="color: rgb(55, 65, 81);">Hàng&nbsp;năm,&nbsp;vào&nbsp;các&nbsp;ngày&nbsp;mùng&nbsp;8,&nbsp;mùng&nbsp;9,&nbsp;mùng&nbsp;10&nbsp;tháng&nbsp;6&nbsp;âm&nbsp;lịch,&nbsp;lễ&nbsp;giỗ&nbsp;ông&nbsp;bà&nbsp;Đỗ&nbsp;Công&nbsp;Tường&nbsp;được&nbsp;chính&nbsp;quyền&nbsp;và&nbsp;nhân&nbsp;dân&nbsp;tổ&nbsp;chức&nbsp;rất&nbsp;trang&nbsp;trọng.&nbsp;Dịp&nbsp;này,&nbsp;nhiều&nbsp;hoạt&nbsp;động&nbsp;lễ&nbsp;hội&nbsp;diễn&nbsp;ra&nbsp;thu&nbsp;hút&nbsp;hàng&nbsp;chục&nbsp;ngàn&nbsp;người&nbsp;dân&nbsp;trong&nbsp;và&nbsp;ngoài&nbsp;tỉnh&nbsp;đến&nbsp;thắp&nbsp;hương&nbsp;chiêm&nbsp;bái&nbsp;và&nbsp;tham&nbsp;gia&nbsp;lễ&nbsp;hội.&nbsp;Sắc&nbsp;thần&nbsp;được&nbsp;thỉnh&nbsp;vòng&nbsp;qua&nbsp;các&nbsp;đường&nbsp;phố&nbsp;của&nbsp;TP&nbsp;Cao&nbsp;Lãnh&nbsp;với&nbsp;kiệu&nbsp;rước,&nbsp;nghi&nbsp;trượng,&nbsp;cờ&nbsp;tiết,&nbsp;tàn&nbsp;lọng&nbsp;trang&nbsp;nghiêm.</span></p><p class="ql-align-justify"><span style="color: rgb(55, 65, 81);">Những&nbsp;năm&nbsp;gần&nbsp;đây,&nbsp;lễ&nbsp;giỗ&nbsp;ông&nbsp;bà&nbsp;thu&nbsp;hút&nbsp;người&nbsp;dân&nbsp;từ&nbsp;các&nbsp;tỉnh&nbsp;miền&nbsp;Trung,&nbsp;miền&nbsp;Bắc&nbsp;đến&nbsp;tham&nbsp;dự&nbsp;ngày&nbsp;càng&nbsp;đông.&nbsp;Lễ&nbsp;giỗ&nbsp;cũng&nbsp;được&nbsp;mở&nbsp;rộng&nbsp;quy&nbsp;mô&nbsp;về&nbsp;phần&nbsp;hội&nbsp;với&nbsp;nhiều&nbsp;hoạt&nbsp;động&nbsp;văn&nbsp;hóa,&nbsp;văn&nbsp;nghệ,&nbsp;thể&nbsp;dục&nbsp;thể&nbsp;thao&nbsp;phục&nbsp;vụ&nbsp;nhân&nbsp;dân&nbsp;trong&nbsp;suốt&nbsp;3&nbsp;ngày&nbsp;lễ&nbsp;hội.&nbsp;Đây&nbsp;được&nbsp;xem&nbsp;là&nbsp;lễ&nbsp;hội&nbsp;tiêu&nbsp;biểu&nbsp;cho&nbsp;truyền&nbsp;thống&nbsp;uống&nbsp;nước&nbsp;nhớ&nbsp;nguồn,&nbsp;tri&nbsp;ân&nbsp;và&nbsp;tôn&nbsp;kính&nbsp;đối&nbsp;với&nbsp;bậc&nbsp;tiền&nbsp;nhân&nbsp;có&nbsp;công&nbsp;với&nbsp;quê&nbsp;hương,&nbsp;đất&nbsp;nước,&nbsp;là&nbsp;di&nbsp;sản&nbsp;văn&nbsp;hóa&nbsp;phi&nbsp;vật&nbsp;thể&nbsp;tiêu&nbsp;biểu&nbsp;của&nbsp;thành&nbsp;phố&nbsp;Cao&nbsp;Lãnh&nbsp;và&nbsp;tỉnh&nbsp;Đồng&nbsp;Tháp.</span></p><p class="ql-align-justify"><span style="color: rgb(55, 65, 81);">Đền&nbsp;thờ&nbsp;ông&nbsp;bà&nbsp;Đỗ&nbsp;Công&nbsp;Tường&nbsp;ngày&nbsp;nay&nbsp;như&nbsp;một&nbsp;di&nbsp;tích&nbsp;lưu&nbsp;lại&nbsp;dấu&nbsp;ấn&nbsp;tiền&nbsp;nhân&nbsp;thời&nbsp;kỳ&nbsp;khẩn&nbsp;hoang&nbsp;lập&nbsp;ấp&nbsp;của&nbsp;vùng&nbsp;đất&nbsp;Cao&nbsp;Lãnh&nbsp;nói&nbsp;riêng&nbsp;và&nbsp;Nam&nbsp;Bộ&nbsp;nói&nbsp;chung.&nbsp;Di&nbsp;tích&nbsp;ngoài&nbsp;thể&nbsp;hiện&nbsp;tín&nbsp;ngưỡng&nbsp;của&nbsp;nhân&nbsp;dân&nbsp;đối&nbsp;với&nbsp;bậc&nbsp;tiền&nbsp;nhân&nbsp;có&nbsp;nhiều&nbsp;công&nbsp;lao&nbsp;với&nbsp;quê&nbsp;hương,&nbsp;còn&nbsp;lưu&nbsp;giữ&nbsp;giá&nbsp;trị&nbsp;vật&nbsp;chất&nbsp;lẫn&nbsp;tinh&nbsp;thần&nbsp;đối&nbsp;với&nbsp;người&nbsp;dân&nbsp;miền&nbsp;đất&nbsp;này.</span></p>', 1, 4, N'Draft', CAST(N'2026-03-24T18:34:47.7335790' AS DateTime2), NULL, N'Tên gọi Cao Lãnh gắn liền với câu chuyện lịch sử về ông Đỗ Công Tường – người được tôn là Thành hoàng.', N'/uploads/a35f5176-848c-4769-ad28-cceb4d89980f.jpg')
INSERT [dbo].[Articles] ([Id], [Title], [Slug], [Content], [CategoryId], [AuthorId], [Status], [CreatedAt], [PublishedAt], [Excerpt], [FeaturedImage]) VALUES (7, N'Phát triển du lịch gắn với văn hóa và sinh thái tại Cao Lãnh', N'du-lich-cao-lanh-dong-thap', N'<p class="ql-align-justify"><span style="background-color: rgb(255, 255, 255); color: rgb(42, 56, 74);">Thời&nbsp;gian&nbsp;qua,&nbsp;công&nbsp;tác&nbsp;bảo&nbsp;tồn,&nbsp;gìn&nbsp;giữ&nbsp;và&nbsp;phát&nbsp;huy&nbsp;các&nbsp;giá&nbsp;trị&nbsp;văn&nbsp;hóa&nbsp;trên&nbsp;địa&nbsp;bàn&nbsp;TP&nbsp;Cao&nbsp;Lãnh&nbsp;(tỉnh&nbsp;Đồng&nbsp;Tháp)&nbsp;được&nbsp;chú&nbsp;trọng&nbsp;khai&nbsp;thác,&nbsp;nhất&nbsp;là&nbsp;phát&nbsp;huy&nbsp;thế&nbsp;mạnh&nbsp;các&nbsp;di&nbsp;sản&nbsp;văn&nbsp;hóa&nbsp;kết&nbsp;hợp&nbsp;với&nbsp;phát&nbsp;triển&nbsp;du&nbsp;lịch,&nbsp;dịch&nbsp;vụ&nbsp;góp&nbsp;phần&nbsp;thúc&nbsp;đẩy&nbsp;phát&nbsp;triển&nbsp;kinh&nbsp;tế&nbsp;-&nbsp;xã&nbsp;hội&nbsp;của&nbsp;địa&nbsp;phương.&nbsp;Công&nbsp;tác&nbsp;bảo&nbsp;tồn&nbsp;và&nbsp;phát&nbsp;huy&nbsp;các&nbsp;giá&nbsp;trị&nbsp;lịch&nbsp;sử&nbsp;văn&nbsp;hóa&nbsp;trên&nbsp;địa&nbsp;bàn&nbsp;thành&nbsp;phố&nbsp;thường&nbsp;xuyên&nbsp;được&nbsp;khảo&nbsp;sát,&nbsp;tổ&nbsp;chức&nbsp;tọa&nbsp;đàm&nbsp;về&nbsp;nghi&nbsp;thức&nbsp;lễ,&nbsp;trang&nbsp;trí&nbsp;các&nbsp;câu&nbsp;liễn&nbsp;đối,&nbsp;hoành&nbsp;phi&nbsp;nhằm&nbsp;giữ&nbsp;gìn&nbsp;và&nbsp;phát&nbsp;huy&nbsp;giá&nbsp;trị&nbsp;lịch&nbsp;sử&nbsp;của&nbsp;các&nbsp;di&nbsp;tích,&nbsp;nhất&nbsp;là&nbsp;gắn&nbsp;với&nbsp;phát&nbsp;triển&nbsp;sản&nbsp;xuất&nbsp;và&nbsp;kinh&nbsp;doanh&nbsp;trên&nbsp;địa&nbsp;bàn&nbsp;thành&nbsp;phố.</span></p><p class="ql-align-center"><u style="background-color: rgb(255, 255, 255); color: rgb(13, 110, 253);"><a href="https://images.vietnamtourism.gov.vn/vn//images/2021/thang_12/3112.di-tich-lich-su-do-cong-tuong.jpg" rel="noopener noreferrer" target="_blank"><img src="https://images.vietnamtourism.gov.vn/vn//images/2021/thang_12/3112.di-tich-lich-su-do-cong-tuong.jpg"></a></u></p><p class="ql-align-center"><em style="background-color: rgb(255, 255, 255); color: rgb(33, 37, 41);">Di&nbsp;tích&nbsp;lịch&nbsp;sử&nbsp;Mộ&nbsp;và&nbsp;Đền&nbsp;thờ&nbsp;ông,&nbsp;bà&nbsp;Đỗ&nbsp;Công&nbsp;Tường&nbsp;được&nbsp;xếp&nbsp;hạng&nbsp;cấp&nbsp;Quốc&nbsp;gia.&nbsp;</em><span style="background-color: rgb(255, 255, 255); color: rgb(33, 37, 41);">Ảnh:&nbsp;D.C</span></p><p class="ql-align-justify"><span style="background-color: rgb(255, 255, 255); color: rgb(33, 37, 41);">Chẳng&nbsp;hạn,&nbsp;phát&nbsp;huy&nbsp;giá&nbsp;trị&nbsp;lịch&nbsp;sử&nbsp;văn&nbsp;hóa&nbsp;đối&nbsp;với&nbsp;Di&nbsp;tích&nbsp;lịch&nbsp;sử&nbsp;Mộ&nbsp;và&nbsp;Đền&nbsp;thờ&nbsp;ông,&nbsp;bà&nbsp;Đỗ&nbsp;Công&nbsp;Tường&nbsp;tọa&nbsp;lạc&nbsp;Phường&nbsp;2,&nbsp;TP&nbsp;Cao&nbsp;Lãnh&nbsp;được&nbsp;UBND&nbsp;tỉnh&nbsp;Đồng&nbsp;Tháp&nbsp;công&nbsp;nhận&nbsp;là&nbsp;Di&nbsp;tích&nbsp;lịch&nbsp;sử&nbsp;văn&nbsp;hóa&nbsp;cấp&nbsp;tỉnh.&nbsp;Hàng&nbsp;năm,&nbsp;Ban&nbsp;Tế&nbsp;tự,&nbsp;Ban&nbsp;Quản&nbsp;lý&nbsp;di&nbsp;tích&nbsp;cùng&nbsp;chính&nbsp;quyền&nbsp;trang&nbsp;trọng&nbsp;tổ&nbsp;chức&nbsp;lễ&nbsp;giỗ&nbsp;ông,&nbsp;bà&nbsp;Đỗ&nbsp;Công&nbsp;Tường&nbsp;và&nbsp;được&nbsp;đông&nbsp;đảo&nbsp;người&nbsp;dân&nbsp;trong&nbsp;và&nbsp;ngoài&nbsp;địa&nbsp;phương&nbsp;đến&nbsp;cúng&nbsp;viếng,&nbsp;tham&nbsp;quan.&nbsp;Theo&nbsp;tài&nbsp;liệu,&nbsp;ông&nbsp;Đỗ&nbsp;Công&nbsp;Tường&nbsp;tục&nbsp;danh&nbsp;là&nbsp;Lãnh&nbsp;cùng&nbsp;vợ&nbsp;đến&nbsp;lập&nbsp;nghiệp&nbsp;tại&nbsp;thôn&nbsp;Mỹ&nbsp;Trà&nbsp;khoảng&nbsp;đầu&nbsp;đời&nbsp;Gia&nbsp;Long.&nbsp;Ông&nbsp;khai&nbsp;khẩn&nbsp;đất&nbsp;hoang,&nbsp;trồng&nbsp;cây,&nbsp;không&nbsp;bao&nbsp;lâu&nbsp;khá&nbsp;lên&nbsp;nhờ&nbsp;nguồn&nbsp;thu&nbsp;từ&nbsp;vườn&nbsp;quýt.&nbsp;Vườn&nbsp;quýt&nbsp;của&nbsp;ông&nbsp;bà&nbsp;rộng&nbsp;rãi,&nbsp;mát&nbsp;mẻ,&nbsp;thuận&nbsp;tiện&nbsp;cả&nbsp;đường&nbsp;sông&nbsp;lẫn&nbsp;đường&nbsp;bộ&nbsp;nên&nbsp;người&nbsp;dân&nbsp;trong&nbsp;thôn&nbsp;thường&nbsp;họp&nbsp;ở&nbsp;đây&nbsp;để&nbsp;mua&nbsp;bán,&nbsp;lâu&nbsp;dần&nbsp;thành&nbsp;chợ.&nbsp;Thấy&nbsp;ông&nbsp;có&nbsp;tính&nbsp;cương&nbsp;trực,&nbsp;lại&nbsp;thông&nbsp;thuộc&nbsp;kinh&nbsp;sách&nbsp;nên&nbsp;người&nbsp;dân&nbsp;cử&nbsp;ông&nbsp;giữ&nbsp;chức&nbsp;Câu&nbsp;Đương,&nbsp;trông&nbsp;coi&nbsp;việc&nbsp;phân&nbsp;xử&nbsp;những&nbsp;vụ&nbsp;tranh&nbsp;tụng&nbsp;nhỏ&nbsp;trong&nbsp;thôn.&nbsp;Từ&nbsp;đó,&nbsp;người&nbsp;người&nbsp;quen&nbsp;gọi&nbsp;chức&nbsp;vụ&nbsp;và&nbsp;tên&nbsp;tục&nbsp;của&nbsp;ông&nbsp;là&nbsp;Câu&nbsp;Lãnh.&nbsp;Còn&nbsp;khu&nbsp;chợ&nbsp;Vườn&nbsp;Quýt&nbsp;cũng&nbsp;được&nbsp;người&nbsp;dân&nbsp;gọi&nbsp;tên&nbsp;là&nbsp;chợ&nbsp;Ông&nbsp;Câu&nbsp;hay&nbsp;chợ&nbsp;Câu&nbsp;Lãnh,&nbsp;dần&nbsp;dần&nbsp;nói&nbsp;trại&nbsp;thành&nbsp;Cao&nbsp;Lãnh.&nbsp;Công&nbsp;lao&nbsp;thành&nbsp;lập&nbsp;chợ&nbsp;của&nbsp;ông&nbsp;bà&nbsp;cũng&nbsp;được&nbsp;triều&nbsp;đình&nbsp;phong&nbsp;kiến&nbsp;nhà&nbsp;Nguyễn&nbsp;ghi&nbsp;nhận&nbsp;thông&nbsp;qua&nbsp;bản&nbsp;sắc&nbsp;phong&nbsp;của&nbsp;vua&nbsp;Tự&nbsp;Đức&nbsp;năm&nbsp;1935:&nbsp;“Sắc&nbsp;cho&nbsp;xã&nbsp;Mỹ&nbsp;Trà,&nbsp;tỉnh&nbsp;Sa&nbsp;Đéc,&nbsp;thờ&nbsp;phụng&nbsp;vị&nbsp;thần&nbsp;có&nbsp;công&nbsp;khai&nbsp;lập&nbsp;chợ&nbsp;Câu&nbsp;Lãnh&nbsp;là&nbsp;Đỗ&nbsp;Công&nbsp;Tường”.&nbsp;Đây&nbsp;cũng&nbsp;là&nbsp;bằng&nbsp;chứng&nbsp;lịch&nbsp;sử&nbsp;có&nbsp;giá&nbsp;trị&nbsp;về&nbsp;công&nbsp;lao&nbsp;của&nbsp;ông&nbsp;bà&nbsp;Đỗ&nbsp;Công&nbsp;Tường&nbsp;đối&nbsp;với&nbsp;vùng&nbsp;đất&nbsp;Cao&nbsp;Lãnh&nbsp;ngày&nbsp;nay&nbsp;và&nbsp;địa&nbsp;danh&nbsp;ấy&nbsp;đã&nbsp;tồn&nbsp;tại&nbsp;hơn&nbsp;200&nbsp;năm.&nbsp;Ngày&nbsp;8/7/2019,&nbsp;Bộ&nbsp;Văn&nbsp;hóa,&nbsp;Thể&nbsp;thao&nbsp;và&nbsp;Du&nbsp;lịch&nbsp;quyết&nbsp;định&nbsp;xếp&nbsp;hạng&nbsp;Di&nbsp;tích&nbsp;Quốc&nbsp;gia&nbsp;đối&nbsp;với&nbsp;Di&nbsp;tích&nbsp;lịch&nbsp;sử&nbsp;Mộ&nbsp;và&nbsp;Đền&nbsp;thờ&nbsp;ông,&nbsp;bà&nbsp;Đỗ&nbsp;Công&nbsp;Tường.</span></p><p class="ql-align-justify"><span style="background-color: rgb(255, 255, 255); color: rgb(33, 37, 41);">Ông&nbsp;Nguyễn&nbsp;Văn&nbsp;Thành&nbsp;ngụ&nbsp;ấp&nbsp;Hòa&nbsp;Dân,&nbsp;xã&nbsp;Nhị&nbsp;Mỹ,&nbsp;huyện&nbsp;Cao&nbsp;Lãnh&nbsp;cho&nbsp;biết:&nbsp;“Nhiều&nbsp;năm&nbsp;trước&nbsp;đây,&nbsp;gia&nbsp;đình&nbsp;tôi&nbsp;thường&nbsp;mang&nbsp;lễ&nbsp;vật&nbsp;do&nbsp;nhà&nbsp;trồng&nbsp;(xoài&nbsp;và&nbsp;thanh&nbsp;long)&nbsp;lên&nbsp;cúng&nbsp;viếng&nbsp;ông,&nbsp;bà&nbsp;Chủ&nbsp;chợ&nbsp;vào&nbsp;ngày&nbsp;giỗ&nbsp;ông,&nbsp;bà.&nbsp;Do&nbsp;tình&nbsp;hình&nbsp;dịch&nbsp;bệnh&nbsp;Covid-19&nbsp;diễn&nbsp;biến&nbsp;khá&nbsp;phức&nbsp;tạp&nbsp;nên&nbsp;dịp&nbsp;lễ&nbsp;giỗ&nbsp;ông,&nbsp;bà&nbsp;Đỗ&nbsp;Công&nbsp;Tường&nbsp;lần&nbsp;thứ&nbsp;201&nbsp;(năm&nbsp;2021)&nbsp;tại&nbsp;Di&nbsp;tích&nbsp;Quốc&nbsp;gia&nbsp;Mộ&nbsp;và&nbsp;Đền&nbsp;thờ&nbsp;ông,&nbsp;bà&nbsp;Đỗ&nbsp;Công&nbsp;Tường,&nbsp;gia&nbsp;đình&nbsp;tôi&nbsp;chỉ&nbsp;thắp&nbsp;hương,&nbsp;cầu&nbsp;nguyện&nbsp;tại&nbsp;nhà.&nbsp;Gần&nbsp;đây,&nbsp;tình&nbsp;hình&nbsp;dịch&nbsp;bệnh&nbsp;được&nbsp;kiểm&nbsp;soát&nbsp;tốt&nbsp;nên&nbsp;gia&nbsp;đình&nbsp;tôi&nbsp;đến&nbsp;và&nbsp;được&nbsp;Ban&nbsp;Tế&nbsp;tự&nbsp;hướng&nbsp;dẫn&nbsp;dâng&nbsp;hương&nbsp;tại&nbsp;đền&nbsp;thờ&nbsp;ông,&nbsp;bà&nbsp;đảm&nbsp;bảo&nbsp;đúng&nbsp;theo&nbsp;quy&nbsp;định&nbsp;phòng,&nbsp;chống&nbsp;dịch&nbsp;Covid-19”.&nbsp;Được&nbsp;biết,&nbsp;Di&nbsp;tích&nbsp;lịch&nbsp;sử&nbsp;Mộ&nbsp;và&nbsp;Đền&nbsp;thờ&nbsp;ông,&nbsp;bà&nbsp;Đỗ&nbsp;Công&nbsp;Tường&nbsp;là&nbsp;một&nbsp;trong&nbsp;những&nbsp;địa&nbsp;điểm&nbsp;diễn&nbsp;ra&nbsp;các&nbsp;hoạt&nbsp;động&nbsp;văn&nbsp;hóa,&nbsp;thể&nbsp;thao&nbsp;của&nbsp;thành&nbsp;phố,&nbsp;dấu&nbsp;ấn&nbsp;là&nbsp;các&nbsp;hoạt&nbsp;động&nbsp;trong&nbsp;Tuần&nbsp;lễ&nbsp;Văn&nbsp;hóa&nbsp;Du&nbsp;lịch&nbsp;Đồng&nbsp;Tháp&nbsp;năm&nbsp;2019.&nbsp;Hàng&nbsp;năm,&nbsp;Di&nbsp;tích&nbsp;lịch&nbsp;sử&nbsp;Mộ&nbsp;và&nbsp;Đền&nbsp;thờ&nbsp;ông,&nbsp;bà&nbsp;Đỗ&nbsp;Công&nbsp;Tường&nbsp;thu&nbsp;hút&nbsp;hàng&nbsp;chục&nbsp;ngàn&nbsp;lượt&nbsp;khách&nbsp;trong&nbsp;và&nbsp;ngoài&nbsp;tỉnh&nbsp;đến&nbsp;cúng&nbsp;viếng,&nbsp;tham&nbsp;quan.</span></p><p class="ql-align-justify"><span style="background-color: rgb(255, 255, 255); color: rgb(33, 37, 41);">Song&nbsp;song&nbsp;với&nbsp;việc&nbsp;khai&nbsp;thác&nbsp;giá&nbsp;trị&nbsp;di&nbsp;sản&nbsp;văn&nbsp;hóa,&nbsp;TP&nbsp;Cao&nbsp;Lãnh&nbsp;cũng&nbsp;quan&nbsp;tâm&nbsp;khai&nbsp;thác&nbsp;du&nbsp;lịch&nbsp;sinh&nbsp;thái&nbsp;-&nbsp;ẩm&nbsp;thực;&nbsp;trải&nbsp;nghiệm&nbsp;-&nbsp;nghỉ&nbsp;dưỡng&nbsp;trên&nbsp;địa&nbsp;bàn.&nbsp;Nhất&nbsp;là&nbsp;hình&nbsp;thành&nbsp;các&nbsp;điểm&nbsp;du&nbsp;lịch&nbsp;cộng&nbsp;đồng&nbsp;tại&nbsp;xã&nbsp;Tân&nbsp;Thuận&nbsp;Đông;&nbsp;các&nbsp;điểm&nbsp;tham&nbsp;quan&nbsp;như:&nbsp;Công&nbsp;viên&nbsp;-&nbsp;Quảng&nbsp;trường&nbsp;Văn&nbsp;Miếu,&nbsp;Cơ&nbsp;sở&nbsp;sản&nbsp;xuất&nbsp;nấm&nbsp;đông&nbsp;trùng&nbsp;hạ&nbsp;thảo&nbsp;An&nbsp;An;&nbsp;Cơ&nbsp;sở&nbsp;đinh&nbsp;lăng&nbsp;Mộc&nbsp;Gia&nbsp;Phát,&nbsp;Vườn&nbsp;mận&nbsp;Hòa&nbsp;An,&nbsp;homestay&nbsp;tại&nbsp;Thuận&nbsp;Tân&nbsp;Hội&nbsp;quán&nbsp;(xã&nbsp;Tân&nbsp;Thuận&nbsp;Tây)&nbsp;cùng&nbsp;với&nbsp;các&nbsp;điểm&nbsp;di&nbsp;tích&nbsp;lịch&nbsp;sử&nbsp;-&nbsp;văn&nbsp;hóa&nbsp;từng&nbsp;bước&nbsp;được&nbsp;trùng&nbsp;tu&nbsp;để&nbsp;liên&nbsp;kết&nbsp;triển&nbsp;khai&nbsp;các&nbsp;sản&nbsp;phẩm&nbsp;du&nbsp;lịch,&nbsp;giới&nbsp;thiệu&nbsp;đến&nbsp;du&nbsp;khách&nbsp;trong&nbsp;và&nbsp;ngoài&nbsp;tỉnh.&nbsp;Đặc&nbsp;biệt,&nbsp;điểm&nbsp;tham&nbsp;quan&nbsp;Làng&nbsp;Bích&nbsp;họa&nbsp;Hữu&nbsp;Nghị&nbsp;Việt&nbsp;-&nbsp;Úc&nbsp;dưới&nbsp;chân&nbsp;cầu&nbsp;Cao&nbsp;Lãnh&nbsp;được&nbsp;triển&nbsp;khai&nbsp;do&nbsp;Đại&nbsp;Sứ&nbsp;quán&nbsp;Úc&nbsp;tại&nbsp;Việt&nbsp;Nam&nbsp;phối&nbsp;hợp&nbsp;thực&nbsp;hiện.&nbsp;Đây&nbsp;là&nbsp;mô&nbsp;hình&nbsp;du&nbsp;lịch&nbsp;cộng&nbsp;đồng&nbsp;được&nbsp;khánh&nbsp;thành&nbsp;đầu&nbsp;tiên&nbsp;tại&nbsp;đồng&nbsp;bằng&nbsp;sông&nbsp;Cửu&nbsp;Long,&nbsp;không&nbsp;chỉ&nbsp;mang&nbsp;tính&nbsp;chất&nbsp;biểu&nbsp;trưng&nbsp;thu&nbsp;hút&nbsp;truyền&nbsp;thông&nbsp;quảng&nbsp;bá&nbsp;về&nbsp;hai&nbsp;nền&nbsp;văn&nbsp;hóa&nbsp;Việt&nbsp;Nam&nbsp;-&nbsp;Australia&nbsp;mà&nbsp;còn&nbsp;góp&nbsp;phần&nbsp;quảng&nbsp;bá&nbsp;về&nbsp;vùng&nbsp;Đất&nbsp;Sen&nbsp;hồng&nbsp;đến&nbsp;với&nbsp;du&nbsp;khách&nbsp;trong&nbsp;và&nbsp;ngoài&nbsp;nước.</span></p><p class="ql-align-justify"><span style="background-color: rgb(255, 255, 255); color: rgb(33, 37, 41);">Thời&nbsp;gian&nbsp;tới,&nbsp;địa&nbsp;phương&nbsp;tiếp&nbsp;tục&nbsp;triển&nbsp;khai&nbsp;thực&nbsp;hiện&nbsp;về&nbsp;phát&nbsp;triển&nbsp;du&nbsp;lịch&nbsp;thành&nbsp;phố&nbsp;đến&nbsp;năm&nbsp;2025,&nbsp;định&nbsp;hướng&nbsp;đến&nbsp;năm&nbsp;2030&nbsp;gắn&nbsp;với&nbsp;đề&nbsp;án&nbsp;phát&nbsp;triển&nbsp;du&nbsp;lịch&nbsp;của&nbsp;tỉnh&nbsp;Đồng&nbsp;Tháp.&nbsp;Thành&nbsp;phố&nbsp;tập&nbsp;trung&nbsp;phát&nbsp;triển&nbsp;du&nbsp;lịch&nbsp;ở&nbsp;3&nbsp;khu&nbsp;vực:&nbsp;mở&nbsp;rộng&nbsp;không&nbsp;gian&nbsp;văn&nbsp;hóa&nbsp;-&nbsp;lễ&nbsp;hội&nbsp;gắn&nbsp;với&nbsp;tổ&nbsp;chức&nbsp;các&nbsp;hoạt&nbsp;động,&nbsp;sự&nbsp;kiện&nbsp;tại&nbsp;Phường&nbsp;1,&nbsp;Phường&nbsp;2&nbsp;và&nbsp;Phường&nbsp;4;&nbsp;phát&nbsp;triển&nbsp;du&nbsp;lịch&nbsp;nông&nbsp;nghiệp,&nbsp;du&nbsp;lịch&nbsp;sinh&nbsp;thái,&nbsp;du&nbsp;lịch&nbsp;trải&nbsp;nghiệm,&nbsp;du&nbsp;lịch&nbsp;miệt&nbsp;vườn&nbsp;kết&nbsp;hợp&nbsp;homestay&nbsp;tại&nbsp;xã&nbsp;Tân&nbsp;Thuận&nbsp;Đông&nbsp;và&nbsp;xã&nbsp;Tân&nbsp;Thuận&nbsp;Tây;&nbsp;du&nbsp;lịch&nbsp;trải&nbsp;nghiệm&nbsp;gắn&nbsp;với&nbsp;làng&nbsp;nghề&nbsp;truyền&nbsp;thống&nbsp;tại&nbsp;xã&nbsp;Mỹ&nbsp;Trà&nbsp;và&nbsp;xã&nbsp;Mỹ&nbsp;Tân.&nbsp;Tiếp&nbsp;tục&nbsp;thực&nbsp;hiện&nbsp;tốt&nbsp;công&nbsp;tác&nbsp;khôi&nbsp;phục,&nbsp;bảo&nbsp;tồn&nbsp;và&nbsp;phát&nbsp;huy&nbsp;các&nbsp;giá&nbsp;trị&nbsp;truyền&nbsp;thống&nbsp;của&nbsp;các&nbsp;di&nbsp;tích&nbsp;lịch&nbsp;sử,&nbsp;các&nbsp;địa&nbsp;điểm&nbsp;du&nbsp;lịch&nbsp;và&nbsp;làng&nbsp;nghề&nbsp;trên&nbsp;địa&nbsp;bàn;&nbsp;đồng&nbsp;thời&nbsp;kết&nbsp;nối&nbsp;các&nbsp;công&nbsp;ty&nbsp;lữ&nbsp;hành&nbsp;xây&nbsp;dựng&nbsp;tour,&nbsp;tuyến&nbsp;điểm&nbsp;tham&nbsp;quan&nbsp;các&nbsp;di&nbsp;tích&nbsp;lịch&nbsp;sử&nbsp;văn&nbsp;hóa&nbsp;trên&nbsp;địa&nbsp;bàn&nbsp;thành&nbsp;phố.</span></p><p></p>', 1, 4, N'Draft', CAST(N'2026-03-24T18:49:36.0669212' AS DateTime2), NULL, N'Cao Lãnh đẩy mạnh phát triển du lịch sinh thái, văn hóa và trải nghiệm.', N'/uploads/a9b92bdc-ad3f-44bf-a88c-4cdb15a22198.jpg')
INSERT [dbo].[Articles] ([Id], [Title], [Slug], [Content], [CategoryId], [AuthorId], [Status], [CreatedAt], [PublishedAt], [Excerpt], [FeaturedImage]) VALUES (8, N'50 năm thống nhất đất nước: "Địa chỉ đỏ" Địa điểm Tập kết ra Bắc tại Cao Lãnh', N'50-nam-thong-nhat-dat-nuoc-dia-chi-do-dia-diem-tap-ket-ra-bac-tai-cao-lanh', N'<p><span style="background-color: rgb(255, 255, 255); color: rgb(34, 34, 34);">Cách&nbsp;đây&nbsp;71&nbsp;năm,&nbsp;sự&nbsp;kiện&nbsp;tập&nbsp;kết&nbsp;chuyển&nbsp;quân&nbsp;tại&nbsp;Cao&nbsp;Lãnh&nbsp;đánh&nbsp;dấu&nbsp;bước&nbsp;ngoặt&nbsp;trong&nbsp;lịch&nbsp;sử&nbsp;cả&nbsp;nước&nbsp;nói&nbsp;chung,&nbsp;tỉnh&nbsp;Đồng&nbsp;Tháp&nbsp;nói&nbsp;riêng.</span></p><p><span style="background-color: rgb(255, 255, 255); color: rgb(34, 34, 34);">Di&nbsp;tích&nbsp;lịch&nbsp;sử&nbsp;quốc&nbsp;gia&nbsp;Địa&nbsp;điểm&nbsp;Tập&nbsp;kết&nbsp;ra&nbsp;Bắc&nbsp;năm&nbsp;1954&nbsp;tại&nbsp;Cao&nbsp;Lãnh&nbsp;(phường&nbsp;6,&nbsp;thành&nbsp;phố&nbsp;Cao&nbsp;Lãnh,&nbsp;tỉnh&nbsp;Đồng&nbsp;Tháp)&nbsp;trở&nbsp;thành&nbsp;“địa&nbsp;chỉ&nbsp;đỏ”&nbsp;góp&nbsp;phần&nbsp;giáo&nbsp;dục&nbsp;truyền&nbsp;thống&nbsp;cách&nbsp;mạng&nbsp;cho&nbsp;cán&nbsp;bộ,&nbsp;đảng&nbsp;viên&nbsp;và&nbsp;nhân&nbsp;dân,&nbsp;nhất&nbsp;là&nbsp;thế&nbsp;hệ&nbsp;trẻ.</span></p><h2><span style="background-color: rgb(255, 255, 255); color: rgb(34, 34, 34);">Nơi&nbsp;ghi&nbsp;dấu&nbsp;lịch&nbsp;sử&nbsp;năm&nbsp;xưa</span></h2><p><span style="background-color: rgb(255, 255, 255); color: rgb(34, 34, 34);">Suốt&nbsp;chín&nbsp;năm&nbsp;(1946-1954),&nbsp;quân&nbsp;và&nbsp;dân&nbsp;ta&nbsp;chịu&nbsp;nhiều&nbsp;gian&nbsp;khổ,&nbsp;hy&nbsp;sinh&nbsp;trong&nbsp;kháng&nbsp;chiến&nbsp;chống&nbsp;thực&nbsp;dân&nbsp;Pháp.</span></p><p><span style="background-color: rgb(255, 255, 255); color: rgb(34, 34, 34);">Dưới&nbsp;sự&nbsp;lãnh&nbsp;đạo&nbsp;sáng&nbsp;suốt&nbsp;của&nbsp;Đảng,&nbsp;quân&nbsp;và&nbsp;dân&nbsp;ta&nbsp;đã&nbsp;làm&nbsp;nên&nbsp;Chiến&nbsp;thắng&nbsp;Điện&nbsp;Biên&nbsp;Phủ&nbsp;“lừng&nbsp;lẫy&nbsp;năm&nbsp;châu,&nbsp;chấn&nbsp;động&nbsp;địa&nbsp;cầu,”&nbsp;góp&nbsp;phần&nbsp;trực&nbsp;tiếp&nbsp;cho&nbsp;sự&nbsp;ra&nbsp;đời&nbsp;của&nbsp;Hiệp&nbsp;định&nbsp;Giơnevơ&nbsp;về&nbsp;việc&nbsp;chấm&nbsp;dứt&nbsp;chiến&nbsp;tranh,&nbsp;lập&nbsp;lại&nbsp;hòa&nbsp;bình&nbsp;ở&nbsp;Việt&nbsp;Nam&nbsp;và&nbsp;toàn&nbsp;Đông&nbsp;Dương.</span></p><p><span style="background-color: rgb(255, 255, 255); color: rgb(34, 34, 34);">Theo&nbsp;Hiệp&nbsp;định&nbsp;Geneve,&nbsp;Nam&nbsp;Bộ&nbsp;có&nbsp;ba&nbsp;khu&nbsp;vực&nbsp;tập&nbsp;kết&nbsp;chuyển&nbsp;quân&nbsp;của&nbsp;Quân&nbsp;đội&nbsp;nhân&nbsp;dân&nbsp;Việt&nbsp;Nam&nbsp;là&nbsp;Hàm&nbsp;Tân-Xuyên&nbsp;Mộc&nbsp;(trong&nbsp;thời&nbsp;gian&nbsp;80&nbsp;ngày);&nbsp;Cao&nbsp;Lãnh,&nbsp;Đồng&nbsp;Tháp&nbsp;Mười&nbsp;(100&nbsp;ngày)&nbsp;và&nbsp;Mũi&nbsp;Cà&nbsp;Mau&nbsp;(200&nbsp;ngày).</span></p><p><span style="background-color: rgb(255, 255, 255); color: rgb(34, 34, 34);">Thị&nbsp;trấn&nbsp;Cao&nbsp;Lãnh,&nbsp;tỉnh&nbsp;Long&nbsp;Châu&nbsp;Sa&nbsp;(nay&nbsp;là&nbsp;thành&nbsp;phố&nbsp;Cao&nbsp;Lãnh,&nbsp;tỉnh&nbsp;Đồng&nbsp;Tháp)&nbsp;được&nbsp;chọn&nbsp;làm&nbsp;điểm&nbsp;tập&nbsp;kết&nbsp;chuyển&nbsp;quân&nbsp;ra&nbsp;miền&nbsp;Bắc&nbsp;trong&nbsp;100&nbsp;ngày.</span></p><p><span style="background-color: rgb(255, 255, 255); color: rgb(34, 34, 34);">Với&nbsp;tinh&nbsp;thần&nbsp;“Đi&nbsp;vinh&nbsp;quang,&nbsp;ở&nbsp;anh&nbsp;dũng,”&nbsp;tỉnh&nbsp;Long&nbsp;Châu&nbsp;Sa&nbsp;đã&nbsp;đón&nbsp;tiếp&nbsp;và&nbsp;đưa&nbsp;tiễn&nbsp;trên&nbsp;13.500&nbsp;cán&nbsp;bộ,&nbsp;chiến&nbsp;sỹ,&nbsp;con&nbsp;em&nbsp;miền&nbsp;Nam&nbsp;và&nbsp;quân&nbsp;tình&nbsp;nguyện&nbsp;xuống&nbsp;tàu&nbsp;tập&nbsp;kết&nbsp;ra&nbsp;Bắc;&nbsp;trong&nbsp;đó,&nbsp;tỉnh&nbsp;Long&nbsp;Châu&nbsp;Sa&nbsp;có&nbsp;hơn&nbsp;2.500&nbsp;người.</span></p><p><span style="background-color: rgb(255, 255, 255); color: rgb(34, 34, 34);">Ngày&nbsp;29/10/1954,&nbsp;chuyến&nbsp;tàu&nbsp;cuối&nbsp;cùng&nbsp;rời&nbsp;bến&nbsp;phà&nbsp;Cao&nbsp;Lãnh&nbsp;chở&nbsp;đoàn&nbsp;quân&nbsp;tập&nbsp;kết&nbsp;ra&nbsp;Bắc.&nbsp;Các&nbsp;chiến&nbsp;sỹ&nbsp;lên&nbsp;đường&nbsp;ra&nbsp;Bắc&nbsp;học&nbsp;tập&nbsp;và&nbsp;trở&nbsp;về&nbsp;chiến&nbsp;đấu&nbsp;giải&nbsp;phóng&nbsp;quê&nbsp;hương.</span></p><p><span style="background-color: rgb(255, 255, 255); color: rgb(34, 34, 34);">Trong&nbsp;số&nbsp;đó,&nbsp;có&nbsp;người&nbsp;đã&nbsp;hy&nbsp;sinh&nbsp;để&nbsp;bảo&nbsp;vệ&nbsp;miền&nbsp;Bắc,&nbsp;có&nbsp;người&nbsp;mãi&nbsp;mãi&nbsp;nằm&nbsp;lại&nbsp;trên&nbsp;chặng&nbsp;đường&nbsp;về&nbsp;Nam;&nbsp;có&nbsp;người&nbsp;được&nbsp;Đảng,&nbsp;Nhà&nbsp;nước&nbsp;cử&nbsp;đi&nbsp;đào&nbsp;tạo&nbsp;trong&nbsp;và&nbsp;ngoài&nbsp;nước,&nbsp;trở&nbsp;thành&nbsp;cán&nbsp;bộ&nbsp;chủ&nbsp;chốt&nbsp;trên&nbsp;các&nbsp;lĩnh&nbsp;vực:&nbsp;kinh&nbsp;tế,&nbsp;chính&nbsp;trị,&nbsp;quân&nbsp;sự,&nbsp;ngoại&nbsp;giao,&nbsp;văn&nbsp;hóa…</span></p><p><span style="background-color: rgb(255, 255, 255); color: rgb(34, 34, 34);">Là&nbsp;một&nbsp;trong&nbsp;số&nbsp;hơn&nbsp;2.500&nbsp;cán&nbsp;bộ,&nbsp;chiến&nbsp;sỹ,&nbsp;học&nbsp;sinh&nbsp;của&nbsp;tỉnh&nbsp;Long&nbsp;Châu&nbsp;Sa&nbsp;tập&nbsp;kết&nbsp;ra&nbsp;Bắc&nbsp;năm&nbsp;xưa,&nbsp;ông&nbsp;Nguyễn&nbsp;Trung&nbsp;Cang&nbsp;(nguyên&nbsp;Giám&nbsp;đốc&nbsp;Sở&nbsp;Khoa&nbsp;học&nbsp;và&nbsp;Công&nbsp;nghệ&nbsp;tỉnh&nbsp;Đồng&nbsp;Tháp)&nbsp;nhớ&nbsp;lại&nbsp;ngày&nbsp;23/10/1954,&nbsp;đơn&nbsp;vị&nbsp;của&nbsp;ông&nbsp;được&nbsp;lệnh&nbsp;hành&nbsp;quân&nbsp;ra&nbsp;bến&nbsp;phà&nbsp;Cao&nbsp;Lãnh,&nbsp;xuống&nbsp;tàu&nbsp;đi&nbsp;ra&nbsp;miền&nbsp;Bắc.</span></p><p><span style="background-color: rgb(255, 255, 255); color: rgb(34, 34, 34);">Càng&nbsp;đến&nbsp;gần&nbsp;nơi&nbsp;tập&nbsp;kết,&nbsp;người&nbsp;dân&nbsp;tiễn&nbsp;đưa&nbsp;rất&nbsp;đông,&nbsp;đứng&nbsp;hai&nbsp;bên&nbsp;đường&nbsp;vẫy&nbsp;tay&nbsp;chào.&nbsp;Hàng&nbsp;nghìn&nbsp;người&nbsp;đứng&nbsp;trên&nbsp;bờ&nbsp;lưu&nbsp;luyến&nbsp;tiễn&nbsp;đưa,&nbsp;người&nbsp;đi,&nbsp;người&nbsp;ở&nbsp;đồng&nbsp;loạt&nbsp;giơ&nbsp;cao&nbsp;hai&nbsp;ngón&nbsp;tay,&nbsp;với&nbsp;ngụ&nbsp;ý&nbsp;là&nbsp;hẹn&nbsp;hai&nbsp;năm&nbsp;sau&nbsp;sẽ&nbsp;gặp&nbsp;lại&nbsp;(hai&nbsp;năm&nbsp;thi&nbsp;hành&nbsp;Hiệp&nbsp;định&nbsp;Geneve).</span></p><p class="ql-align-center"><span style="background-color: rgb(255, 255, 255); color: rgb(34, 34, 34);"><img src="https://media.vietnamplus.vn/images/321b7337942e1f5c8f6251dc9202086727d9a5f85ef47941c2fc59d4e22932bacdb6d8a6638e2b0182ea3ae38b9bcb0bf749ae5485b78df1be81190d38c86edc/ttxvn-tap-ket-ra-bac-cao-lanh-1.jpg"></span><span style="background-color: rgb(255, 255, 255); color: rgb(53, 125, 215);">Di&nbsp;tích&nbsp;lịch&nbsp;sử&nbsp;quốc&nbsp;gia&nbsp;Địa&nbsp;điểm&nbsp;tập&nbsp;kết&nbsp;ra&nbsp;Bắc&nbsp;năm&nbsp;1954&nbsp;tại&nbsp;Cao&nbsp;Lãnh&nbsp;được&nbsp;xây&nbsp;dựng&nbsp;ở&nbsp;Phường&nbsp;6,&nbsp;thành&nbsp;phố&nbsp;Cao&nbsp;Lãnh&nbsp;(tỉnh&nbsp;Đồng&nbsp;Tháp).&nbsp;(Ảnh:&nbsp;Nhựt&nbsp;An/TTXVN)</span></p><p><span style="background-color: rgb(255, 255, 255); color: rgb(34, 34, 34);">Tuy&nbsp;nhiên&nbsp;mãi&nbsp;đến&nbsp;ngày&nbsp;giải&nbsp;phóng&nbsp;miền&nbsp;Nam,&nbsp;đất&nbsp;nước&nbsp;thống&nbsp;nhất,&nbsp;ông&nbsp;và&nbsp;đồng&nbsp;đội&nbsp;mới&nbsp;được&nbsp;trở&nbsp;về&nbsp;quê&nbsp;hương,&nbsp;không&nbsp;ngờ&nbsp;lời&nbsp;hẹn&nbsp;hai&nbsp;năm&nbsp;lại&nbsp;trở&nbsp;thành&nbsp;21&nbsp;năm&nbsp;dài&nbsp;đằng&nbsp;đẵng.</span></p><p><span style="background-color: rgb(255, 255, 255); color: rgb(34, 34, 34);">Sự&nbsp;kiện&nbsp;100&nbsp;ngày&nbsp;tập&nbsp;kết&nbsp;chuyển&nbsp;quân&nbsp;tại&nbsp;Cao&nbsp;Lãnh&nbsp;là&nbsp;cuộc&nbsp;chuyển&nbsp;quân&nbsp;có&nbsp;ý&nbsp;nghĩa&nbsp;to&nbsp;lớn,&nbsp;đưa&nbsp;cán&nbsp;bộ,&nbsp;chiến&nbsp;sỹ,&nbsp;học&nbsp;sinh&nbsp;miền&nbsp;Nam&nbsp;lên&nbsp;tàu&nbsp;rời&nbsp;xa&nbsp;quê&nbsp;hương,&nbsp;cùng&nbsp;nhau&nbsp;ra&nbsp;Bắc&nbsp;lao&nbsp;động,&nbsp;học&nbsp;tập&nbsp;nhằm&nbsp;đóng&nbsp;góp&nbsp;cho&nbsp;cách&nbsp;mạng&nbsp;miền&nbsp;Nam,&nbsp;xây&nbsp;dựng&nbsp;miền&nbsp;Bắc&nbsp;xã&nbsp;hội&nbsp;chủ&nbsp;nghĩa,&nbsp;làm&nbsp;hậu&nbsp;phương&nbsp;vững&nbsp;chắc&nbsp;tiến&nbsp;tới&nbsp;giải&nbsp;phóng&nbsp;miền&nbsp;Nam,&nbsp;thống&nbsp;nhất&nbsp;đất&nbsp;nước.</span></p><p><span style="background-color: rgb(255, 255, 255); color: rgb(34, 34, 34);">100&nbsp;ngày&nbsp;tập&nbsp;kết,&nbsp;chuyển&nbsp;quân&nbsp;tại&nbsp;Cao&nbsp;Lãnh&nbsp;thắm&nbsp;đượm&nbsp;tình&nbsp;quân&nbsp;dân;&nbsp;cùng&nbsp;nhau&nbsp;hướng&nbsp;tới&nbsp;hòa&nbsp;bình,&nbsp;thống&nbsp;nhất,&nbsp;độc&nbsp;lập,&nbsp;dân&nbsp;chủ.</span></p><h2><span style="background-color: rgb(255, 255, 255); color: rgb(34, 34, 34);">“Địa&nbsp;chỉ&nbsp;đỏ”&nbsp;hiện&nbsp;nay</span></h2><p><span style="background-color: rgb(255, 255, 255); color: rgb(34, 34, 34);">Để&nbsp;ghi&nbsp;dấu&nbsp;ấn&nbsp;sự&nbsp;kiện&nbsp;lịch&nbsp;sử&nbsp;trọng&nbsp;đại&nbsp;của&nbsp;đất&nbsp;nước,&nbsp;giáo&nbsp;dục&nbsp;truyền&nbsp;thống&nbsp;cách&nbsp;mạng&nbsp;cho&nbsp;các&nbsp;thế&nbsp;hệ&nbsp;hôm&nbsp;nay&nbsp;và&nbsp;mai&nbsp;sau,&nbsp;tỉnh&nbsp;Đồng&nbsp;Tháp&nbsp;cùng&nbsp;các&nbsp;tỉnh,&nbsp;thành&nbsp;phố&nbsp;có&nbsp;cán&nbsp;bộ,&nbsp;chiến&nbsp;sỹ&nbsp;và&nbsp;con&nbsp;em&nbsp;tập&nbsp;kết&nbsp;tại&nbsp;Cao&nbsp;Lãnh&nbsp;năm&nbsp;1954&nbsp;quyết&nbsp;tâm&nbsp;huy&nbsp;động&nbsp;nguồn&nbsp;lực&nbsp;khởi&nbsp;công&nbsp;xây&nbsp;dựng&nbsp;Tượng&nbsp;đài&nbsp;tưởng&nbsp;niệm&nbsp;sự&nbsp;kiện&nbsp;Tập&nbsp;kết&nbsp;năm&nbsp;1954&nbsp;tại&nbsp;Cao&nbsp;Lãnh&nbsp;và&nbsp;hoàn&nbsp;thành,&nbsp;đưa&nbsp;vào&nbsp;sử&nbsp;dụng&nbsp;trong&nbsp;năm&nbsp;2019.</span></p><p><span style="background-color: rgb(255, 255, 255); color: rgb(34, 34, 34);">Công&nbsp;trình&nbsp;xây&nbsp;dựng&nbsp;trên&nbsp;khuôn&nbsp;viên&nbsp;12.000&nbsp;m2,&nbsp;tổng&nbsp;mức&nbsp;đầu&nbsp;tư&nbsp;khoảng&nbsp;49&nbsp;tỷ&nbsp;đồng.&nbsp;Đến&nbsp;tháng&nbsp;2/2023,&nbsp;Địa&nbsp;điểm&nbsp;Tập&nbsp;kết&nbsp;ra&nbsp;Bắc&nbsp;năm&nbsp;1954&nbsp;tại&nbsp;Cao&nbsp;Lãnh&nbsp;được&nbsp;Bộ&nbsp;Văn&nbsp;hóa,&nbsp;Thể&nbsp;thao&nbsp;và&nbsp;Du&nbsp;lịch&nbsp;quyết&nbsp;định&nbsp;xếp&nbsp;hạng&nbsp;là&nbsp;Di&nbsp;tích&nbsp;lịch&nbsp;sử&nbsp;quốc&nbsp;gia.</span></p><p><span style="background-color: rgb(255, 255, 255); color: rgb(34, 34, 34);">Theo&nbsp;Ủy&nbsp;ban&nbsp;Nhân&nbsp;dân&nbsp;tỉnh&nbsp;Đồng&nbsp;Tháp,&nbsp;công&nbsp;trình&nbsp;Tượng&nbsp;đài&nbsp;sự&nbsp;kiện&nbsp;Tập&nbsp;kết&nbsp;ra&nbsp;Bắc&nbsp;năm&nbsp;1954&nbsp;tại&nbsp;Cao&nbsp;Lãnh&nbsp;là&nbsp;biểu&nbsp;tượng&nbsp;cho&nbsp;lòng&nbsp;tin&nbsp;yêu,&nbsp;sự&nbsp;tri&nbsp;ân&nbsp;của&nbsp;Đảng&nbsp;bộ,&nbsp;chính&nbsp;quyền&nbsp;và&nbsp;nhân&nbsp;dân&nbsp;tỉnh&nbsp;đối&nbsp;với&nbsp;cán&nbsp;bộ,&nbsp;chiến&nbsp;sỹ&nbsp;tập&nbsp;kết&nbsp;năm&nbsp;xưa.</span></p><p><span style="background-color: rgb(255, 255, 255); color: rgb(34, 34, 34);">Công&nbsp;trình&nbsp;có&nbsp;ý&nbsp;nghĩa&nbsp;lịch&nbsp;sử&nbsp;và&nbsp;nhân&nbsp;văn&nbsp;sâu&nbsp;sắc&nbsp;đối&nbsp;với&nbsp;nhân&nbsp;dân&nbsp;Đồng&nbsp;Tháp&nbsp;cũng&nbsp;như&nbsp;khu&nbsp;vực&nbsp;Đồng&nbsp;bằng&nbsp;sông&nbsp;Cửu&nbsp;Long;&nbsp;là&nbsp;nơi&nbsp;để&nbsp;giáo&nbsp;dục&nbsp;truyền&nbsp;thống&nbsp;cách&nbsp;mạng&nbsp;cho&nbsp;cán&nbsp;bộ,&nbsp;đảng&nbsp;viên&nbsp;và&nbsp;nhân&nbsp;dân,&nbsp;nhất&nbsp;là&nbsp;thế&nbsp;hệ&nbsp;trẻ.</span></p><p><span style="background-color: rgb(255, 255, 255); color: rgb(34, 34, 34);">Ủy&nbsp;ban&nbsp;Nhân&nbsp;dân&nbsp;thành&nbsp;phố&nbsp;Cao&nbsp;Lãnh&nbsp;phối&nbsp;hợp&nbsp;với&nbsp;các&nbsp;đơn&nbsp;vị,&nbsp;địa&nbsp;phương&nbsp;liên&nbsp;quan&nbsp;bảo&nbsp;quản,&nbsp;gìn&nbsp;giữ&nbsp;và&nbsp;phát&nbsp;huy&nbsp;giá&nbsp;trị&nbsp;Di&nbsp;tích&nbsp;lịch&nbsp;sử&nbsp;quốc&nbsp;gia&nbsp;này;&nbsp;đồng&nbsp;thời,&nbsp;tổ&nbsp;chức&nbsp;đa&nbsp;dạng&nbsp;các&nbsp;hoạt&nbsp;động&nbsp;nhằm&nbsp;giáo&nbsp;dục&nbsp;truyền&nbsp;thống&nbsp;yêu&nbsp;nước&nbsp;gắn&nbsp;với&nbsp;phát&nbsp;triển&nbsp;du&nbsp;lịch,&nbsp;tạo&nbsp;dựng&nbsp;hình&nbsp;ảnh&nbsp;địa&nbsp;phương.</span></p><p class="ql-align-center"><span style="background-color: rgb(255, 255, 255); color: rgb(34, 34, 34);"><img src="https://media.vietnamplus.vn/images/321b7337942e1f5c8f6251dc9202086727d9a5f85ef47941c2fc59d4e22932bacdb6d8a6638e2b0182ea3ae38b9bcb0b38343fe5ae429df2fc5aeb91fa1c2d78/ttxvn-tap-ket-ra-bac-cao-lanh-3.jpg"></span><span style="background-color: rgb(255, 255, 255); color: rgb(53, 125, 215);">Đoàn&nbsp;viên,&nbsp;thanh&nbsp;niên&nbsp;tỉnh&nbsp;Đồng&nbsp;Tháp&nbsp;tổ&nbsp;chức&nbsp;sinh&nbsp;hoạt&nbsp;Đoàn&nbsp;ở&nbsp;Di&nbsp;tích&nbsp;lịch&nbsp;sử&nbsp;quốc&nbsp;gia&nbsp;Địa&nbsp;điểm&nbsp;tập&nbsp;kết&nbsp;ra&nbsp;Bắc&nbsp;năm&nbsp;1954&nbsp;tại&nbsp;Cao&nbsp;Lãnh.&nbsp;(Ảnh:&nbsp;TTXVN&nbsp;phát)</span></p><p><span style="background-color: rgb(255, 255, 255); color: rgb(34, 34, 34);">Giờ&nbsp;đây,&nbsp;Di&nbsp;tích&nbsp;lịch&nbsp;sử&nbsp;quốc&nbsp;gia&nbsp;Địa&nbsp;điểm&nbsp;Tập&nbsp;kết&nbsp;ra&nbsp;Bắc&nbsp;năm&nbsp;1954&nbsp;tại&nbsp;Cao&nbsp;Lãnh&nbsp;trở&nbsp;thành&nbsp;nơi&nbsp;tổ&nbsp;chức&nbsp;nhiều&nbsp;sự&nbsp;kiện&nbsp;quan&nbsp;trọng&nbsp;của&nbsp;thành&nbsp;phố&nbsp;Cao&nbsp;Lãnh&nbsp;và&nbsp;tỉnh&nbsp;Đồng&nbsp;Tháp.&nbsp;Ban&nbsp;Thường&nbsp;vụ&nbsp;Tỉnh&nbsp;ủy&nbsp;Đồng&nbsp;Tháp&nbsp;đã&nbsp;tổ&nbsp;chức&nbsp;Lễ&nbsp;trao&nbsp;tặng&nbsp;Huy&nbsp;hiệu&nbsp;Đảng&nbsp;cho&nbsp;các&nbsp;đảng&nbsp;viên&nbsp;tại&nbsp;đây.</span></p><p><span style="background-color: rgb(255, 255, 255); color: rgb(34, 34, 34);">Bí&nbsp;thư&nbsp;Tỉnh&nbsp;ủy&nbsp;Đồng&nbsp;Tháp&nbsp;Lê&nbsp;Quốc&nbsp;Phong&nbsp;cho&nbsp;biết&nbsp;thời&nbsp;gian&nbsp;tới,&nbsp;Ban&nbsp;Thường&nbsp;vụ&nbsp;Tỉnh&nbsp;ủy&nbsp;Đồng&nbsp;Tháp&nbsp;tiếp&nbsp;tục&nbsp;tổ&nbsp;chức&nbsp;Lễ&nbsp;trao&nbsp;tặng&nbsp;Huy&nbsp;hiệu&nbsp;Đảng&nbsp;tại&nbsp;các&nbsp;địa&nbsp;danh,&nbsp;di&nbsp;tích&nbsp;lịch&nbsp;sử&nbsp;của&nbsp;tỉnh.&nbsp;Qua&nbsp;đó,&nbsp;giáo&nbsp;dục&nbsp;truyền&nbsp;thống&nbsp;lịch&nbsp;sử&nbsp;và&nbsp;lòng&nbsp;yêu&nbsp;quê&nbsp;hương&nbsp;đất&nbsp;nước&nbsp;cho&nbsp;thế&nbsp;hệ&nbsp;trẻ,&nbsp;ra&nbsp;sức&nbsp;học&nbsp;tập,&nbsp;công&nbsp;tác,&nbsp;cống&nbsp;hiến&nbsp;sức&nbsp;lực,&nbsp;trí&nbsp;tuệ,&nbsp;tài&nbsp;năng&nbsp;cho&nbsp;sự&nbsp;nghiệp&nbsp;xây&nbsp;dựng&nbsp;và&nbsp;bảo&nbsp;vệ&nbsp;Tổ&nbsp;quốc.</span></p><p><span style="background-color: rgb(255, 255, 255); color: rgb(34, 34, 34);">Di&nbsp;tích&nbsp;lịch&nbsp;sử&nbsp;quốc&nbsp;gia&nbsp;Địa&nbsp;điểm&nbsp;Tập&nbsp;kết&nbsp;ra&nbsp;Bắc&nbsp;năm&nbsp;1954&nbsp;tại&nbsp;Cao&nbsp;Lãnh&nbsp;nằm&nbsp;trên&nbsp;cung&nbsp;đường&nbsp;đến&nbsp;chợ&nbsp;quê&nbsp;Tân&nbsp;Thuận&nbsp;Đông&nbsp;(thành&nbsp;phố&nbsp;Cao&nbsp;Lãnh).&nbsp;Do&nbsp;đó,&nbsp;nhiều&nbsp;du&nbsp;khách&nbsp;đã&nbsp;ghé&nbsp;nơi&nbsp;đây&nbsp;tìm&nbsp;hiểu,&nbsp;tham&nbsp;quan,&nbsp;chụp&nbsp;ảnh.</span></p><p><span style="background-color: rgb(255, 255, 255); color: rgb(34, 34, 34);">Các&nbsp;cấp&nbsp;bộ&nbsp;Đoàn&nbsp;trong&nbsp;tỉnh&nbsp;Đồng&nbsp;Tháp&nbsp;cũng&nbsp;thường&nbsp;xuyên&nbsp;chọn&nbsp;di&nbsp;tích&nbsp;lịch&nbsp;sử&nbsp;quốc&nbsp;gia&nbsp;này&nbsp;làm&nbsp;nơi&nbsp;tổ&nbsp;chức&nbsp;các&nbsp;hoạt&nbsp;động&nbsp;của&nbsp;Đoàn.</span></p><p><span style="background-color: rgb(255, 255, 255); color: rgb(34, 34, 34);">Em&nbsp;Lê&nbsp;Trúc&nbsp;Ngọc&nbsp;(sinh&nbsp;viên&nbsp;Trường&nbsp;Đại&nbsp;học&nbsp;Đồng&nbsp;Tháp)&nbsp;bộc&nbsp;bạch,&nbsp;đến&nbsp;với&nbsp;Địa&nbsp;điểm&nbsp;Tập&nbsp;kết&nbsp;ra&nbsp;Bắc&nbsp;năm&nbsp;1954&nbsp;tại&nbsp;Cao&nbsp;Lãnh&nbsp;giúp&nbsp;em&nbsp;hiểu&nbsp;hơn&nbsp;về&nbsp;lịch&nbsp;sử,&nbsp;những&nbsp;nỗ&nbsp;lực,&nbsp;hy&nbsp;sinh&nbsp;của&nbsp;thế&nbsp;hệ&nbsp;đi&nbsp;trước&nbsp;trong&nbsp;quá&nbsp;trình&nbsp;chiến&nbsp;đấu,&nbsp;mang&nbsp;lại&nbsp;độc&nbsp;lập,&nbsp;tự&nbsp;do&nbsp;cho&nbsp;đất&nbsp;nước.&nbsp;Từ&nbsp;đó,&nbsp;em&nbsp;càng&nbsp;trân&nbsp;quý&nbsp;giá&nbsp;trị&nbsp;của&nbsp;hòa&nbsp;bình&nbsp;và&nbsp;thêm&nbsp;yêu&nbsp;quê&nbsp;hương.</span></p><p><span style="background-color: rgb(255, 255, 255); color: rgb(34, 34, 34);">Hơn&nbsp;70&nbsp;năm&nbsp;qua,&nbsp;sự&nbsp;kiện&nbsp;Tập&nbsp;kết&nbsp;ra&nbsp;Bắc&nbsp;năm&nbsp;1954&nbsp;tại&nbsp;Cao&nbsp;Lãnh&nbsp;vẫn&nbsp;còn&nbsp;nguyên&nbsp;giá&nbsp;trị&nbsp;lịch&nbsp;sử.&nbsp;Bài&nbsp;học&nbsp;về&nbsp;tinh&nbsp;thần&nbsp;đoàn&nbsp;kết&nbsp;dân&nbsp;tộc,&nbsp;ý&nbsp;chí&nbsp;quyết&nbsp;tâm,&nbsp;thống&nbsp;nhất&nbsp;của&nbsp;quân&nbsp;dân&nbsp;ta,&nbsp;ra&nbsp;đi&nbsp;vì&nbsp;nghĩa&nbsp;lớn,&nbsp;vì&nbsp;sự&nbsp;nghiệp&nbsp;cách&nbsp;mạng&nbsp;cao&nbsp;cả&nbsp;luôn&nbsp;sáng&nbsp;ngời.</span></p><p><span style="background-color: rgb(255, 255, 255); color: rgb(34, 34, 34);">Nằm&nbsp;bên&nbsp;dòng&nbsp;sông&nbsp;Tiền&nbsp;hiền&nbsp;hòa,&nbsp;Di&nbsp;tích&nbsp;lịch&nbsp;sử&nbsp;quốc&nbsp;gia&nbsp;Địa&nbsp;điểm&nbsp;Tập&nbsp;kết&nbsp;ra&nbsp;Bắc&nbsp;năm&nbsp;1954&nbsp;tại&nbsp;Cao&nbsp;Lãnh&nbsp;vừa&nbsp;là&nbsp;“địa&nbsp;chỉ&nbsp;đỏ”&nbsp;giáo&nbsp;dục&nbsp;truyền&nbsp;thống&nbsp;cách&nbsp;mạng,&nbsp;vừa&nbsp;là&nbsp;điểm&nbsp;đến&nbsp;của&nbsp;người&nbsp;dân&nbsp;và&nbsp;du&nbsp;khách</span></p>', 1, 4, N'Published', CAST(N'2026-03-24T18:53:41.9799121' AS DateTime2), CAST(N'2026-03-24T18:55:07.0655975' AS DateTime2), N'Di tích lịch sử quốc gia Địa điểm Tập kết ra Bắc năm 1954 tại Cao Lãnh (Đồng Tháp) trở thành “địa chỉ đỏ” góp phần giáo dục truyền thống cách mạng cho cán bộ đảng viên và nhân dân, nhất là thế hệ trẻ.', N'/uploads/71ef4651-adec-45c4-b1a1-52903096d59c.jpg')
SET IDENTITY_INSERT [dbo].[Articles] OFF
